INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('0fd8fc10-7dbf-40b4-b33b-c749a0232d64', '6c250523-422a-46f3-a1f1-42e82424897c', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"案例分析：低模与高模的置换烘焙\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"游戏资产\", \"法线贴图\", \"细节传递\", \"性能优化\", \"视觉对比\"], \"depends_on\": [\"p12\"], \"must_cover\": [\"拓扑简化\", \"法线生成\", \"UV展开技巧\", \"材质映射\", \"案例分析：低模与高模的置换烘焙的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"案例分析：低模与高模的置换烘焙的核心概念与背景\", \"案例分析：低模与高模的置换烘焙的关键方法与执行要点\", \"案例分析：低模与高模的置换烘焙的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287042\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'case_study', '{\"title\": \"案例分析：低模与高模的置换烘焙\", \"scenario\": \"在游戏引擎中部署角色或场景资产时，面临高精度细节与实时渲染性能之间的根本矛盾。开发者需在有限三角面数限制下，呈现媲美影视级的表面纹理与几何细节。\", \"challenge\": \"如何在不增加实际多边形数量的前提下，将高模的微小凹凸、划痕、接缝等细节无损传递至低模，并确保法线贴图在不同光照角度下保持视觉一致性？\", \"points\": [{\"title\": \"拓扑简化策略\", \"description\": \"高模保留全部细节用于烘焙源数据，低模则通过智能减面算法保留主体轮廓与功能分区，确保UV展开后纹理映射无拉伸变形，同时控制面数符合目标平台性能阈值。\"}, {\"title\": \"法线生成与UV技巧\", \"description\": \"采用射线投射技术将高模法线信息采样至低模对应位置，生成法线贴图；配合智能UV展开工具优化布局，最大化利用纹理空间，减少接缝可见度并避免重叠区域。\"}, {\"title\": \"材质映射与验证\", \"description\": \"将烘焙结果应用于PBR材质球，结合环境光遮蔽与粗糙度贴图增强立体感；在多种光照条件下测试效果，确保暗部细节不失真、高光过渡自然，最终输出符合引擎规范的贴图序列。\"}], \"conclusion\": \"置换烘焙技术成功解决了视觉 fidelity 与运行效率的冲突，成为现代游戏资产制作的标准范式；其核心在于理解几何数据与纹理数据的分离机制，并通过标准化流程实现跨项目复用。\", \"image\": \"\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
