INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('145b4411-bc4e-41d4-a9f8-5361c61fee28', '7a4f3408-ca73-4a61-998e-174a92497610', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"协作任务：分组设计概念机甲\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"角色分工（主模/细化/贴图）\", \"时间节点控制\", \"产出标准说明\", \"互评机制\", \"协作任务：分组设计概念机甲的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p07_1\"], \"points\": [\"协作任务：分组设计概念机甲的核心概念与背景\", \"协作任务：分组设计概念机甲的关键方法与执行要点\", \"协作任务：分组设计概念机甲的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p07_1\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266790\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:25', 'group_collab', '{\"title\": \"协作任务：分组设计概念机甲\", \"subtitle\": \"从拓扑逻辑到工业级协同实战。\", \"bullets\": [{\"icon\": \"fa-users\", \"text\": \"角色分工与职责界定。\", \"description\": \"明确主模构建、细节刻画与贴图绘制三大核心岗位，确保硬表面布线逻辑与有机体变形需求精准对接。\"}, {\"icon\": \"fa-clock\", \"text\": \"时间节点与流程控制。\", \"description\": \"设定分块思路确认、细节刻画完成及互评修正三个关键里程碑，严格把控从构思到成型的周期。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"产出标准与互评机制。\", \"description\": \"基于四边形面片统一性与支撑边分布建立验收标准，通过跨组互评识别布线冗余与拉伸隐患。\"}, {\"icon\": \"fa-cogs\", \"text\": \"核心概念背景回顾。\", \"description\": \"融合前序章节的视图操作效率与硬表面拓扑策略，将肌肉走向布线逻辑应用于机甲关节设计。\"}], \"keyTakeaway\": \"优秀的硬表面建模不仅依赖工具，更在于对拓扑逻辑的深刻理解与严谨执行，协作是提升工业级渲染质量的关键。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('15698d7f-f028-48db-9695-b29f0cd62e43', 'b494fc12-8d48-4b4c-8717-9faa745d5f79', 0, NULL, '{\"page_id\": \"p01\", \"title\": \"3D建模进阶：从拓扑优化到引擎实时渲染\", \"layout_id\": \"cover_interactive\", \"has_image\": true, \"keywords\": [\"三维网格线框\", \"霓虹光效\", \"极简几何背景\", \"科技感节点\", \"职教绿青橙配色\"], \"depends_on\": [], \"must_cover\": [], \"promises_open\": [{\"promise_id\": \"pr_p01_1\", \"text\": \"解析高模低模转换的核心拓扑逻辑\", \"must_cover\": [\"布线规范\", \"四边面原则\", \"法线修正\"], \"target_page_ids\": [\"p18\"], \"is_hard\": true}, {\"promise_id\": \"pr_p01_2\", \"text\": \"演示游戏引擎中的实时光照与材质流程\", \"must_cover\": [\"PBR工作流\", \"烘焙贴图\", \"LOD设置\"], \"target_page_ids\": [\"p18\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"cover\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 02:23:20', '2026-03-08 02:23:20', 'cover_interactive', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('159621d6-3d2c-4925-ac47-37a707d750c5', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 13, NULL, '{\"page_id\": \"p09\", \"title\": \"初学者软件选择问答\", \"layout_id\": \"edu_qa_case\", \"has_image\": true, \"keywords\": [\"悬浮对话气泡图标\", \"界面截图虚化背景\", \"青色高亮提问框\"], \"depends_on\": [\"p08\"], \"must_cover\": [\"Blender vs Maya\", \"ZBrush 定位\", \"成本考量\", \"初学者软件选择问答的核心概念与背景\", \"初学者软件选择问答的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"初学者软件选择问答的核心概念与背景\", \"初学者软件选择问答的关键方法与执行要点\", \"初学者软件选择问答的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p14\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227850\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_qa_case', '{\"title\": \"初学者软件选择问答\", \"question\": \"初入行业面临多款软件，该如何精准选择？\", \"answer\": \"综合评估预算与目标：免费入门选 Blender，大厂就业选 Maya，生物细节选 ZBrush。\", \"analysis\": [{\"title\": \"Blender vs Maya\", \"content\": \"开源生态 VS 商业垄断，适应不同成本结构与社区支持力度\"}, {\"title\": \"ZBrush 定位\", \"content\": \"作为高模雕刻补充，专注于细节表现，不替代主流程建模\"}, {\"title\": \"成本考量\", \"content\": \"正版授权费差异显著，需权衡学习周期与长期项目投入产出\"}], \"conclusion\": \"选择匹配岗位需求与项目预算的工具组合，避免盲目跟风\", \"variant\": \"c\", \"layout_variant\": \"c\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1599dbe0-3132-4ae1-ac73-ea0975f9a78a', '2210a36d-b61a-453a-83ee-86edc9925e6a', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"标准三维建模工作流图示\", \"layout_id\": \"diagram_illustration\", \"has_image\": true, \"keywords\": [\"流程图节点图标\", \"冷色调连接线\", \"抽象技术管线\", \"结构化架构图\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"白模创建\", \"细分优化\", \"展 UV 流程\", \"标准三维建模工作流图示的核心概念与背景\", \"标准三维建模工作流图示的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"标准三维建模工作流图示的核心概念与背景\", \"标准三维建模工作流图示的关键方法与执行要点\", \"标准三维建模工作流图示的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p06\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647622\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'diagram_illustration', '{\"title\": \"标准三维建模工作流图示\", \"explanations\": [{\"label\": \"白模创建阶段\", \"description\": \"使用低多边形快速搭建主体比例与基本体积感。\"}, {\"label\": \"细分优化步骤\", \"description\": \"通过平滑算法逐步增加细节并优化表面曲线流畅度。\"}, {\"label\": \"UV 展开布局\", \"description\": \"将三维坐标映射为二维纹理空间，减少拉伸变形。\"}], \"summary\": \"标准化的流程闭环能够有效平衡渲染质量与制作工时。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
