INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1db749ad-80d0-4a96-93f5-f88013589bcd', '2210a36d-b61a-453a-83ee-86edc9925e6a', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"核心术语定义与认知\", \"layout_id\": \"key_concepts\", \"has_image\": true, \"keywords\": [\"核心术语定义与认知\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"顶点、边、面定义\", \"模型层级结构\", \"核心术语定义与认知的核心概念与背景\", \"核心术语定义与认知的关键方法与执行要点\", \"核心术语定义与认知的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_p04_topology\", \"text\": \"拓扑布线规则与流形处理\", \"must_cover\": [\"四边形优先原则\", \"极点数量控制\"], \"target_page_ids\": [\"p18\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"核心术语定义与认知的核心概念与背景\", \"核心术语定义与认知的关键方法与执行要点\", \"核心术语定义与认知的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p04\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647589\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'key_concepts', '{\"title\": \"核心术语定义与认知\", \"bullets\": [{\"icon\": \"fa-shapes\", \"text\": \"顶点、边、面基础。\", \"description\": \"网格最小单元，决定几何精度与控制点位置连接关系。\"}, {\"icon\": \"fa-sitemap\", \"text\": \"模型层级结构。\", \"description\": \"对象与组件层级，便于属性管理与高效修改操作。\"}, {\"icon\": \"fa-list-alt\", \"text\": \"命名规范体系。\", \"description\": \"统一前缀标识，显著提升团队协作查找效率。\"}, {\"icon\": \"fa-check-square\", \"text\": \"质量检测清单。\", \"description\": \"确保无破面与开放边界，保证数据一致性。\"}, {\"icon\": \"fa-gamepad\", \"text\": \"应用场景分类。\", \"description\": \"影视资产需高精度拓扑以支撑实时渲染效果。\"}], \"keyTakeaway\": \"准确的术语认知是构建高质量拓扑结构的先决条件。\", \"image\": {\"src\": \"placeholder_geo_model.png\", \"alt\": \"抽象几何拓扑结构示意图\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1e713210-a72b-46ca-a8aa-8c1755c3b16e', 'b494fc12-8d48-4b4c-8717-9faa745d5f79', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"情境模拟：实时渲染中的性能优化挑战\", \"layout_id\": \"role_play_scenario\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p13\"], \"must_cover\": [\"Draw Call优化\", \"遮挡剔除\", \"LOD层级设计\", \"情境模拟：实时渲染中的性能优化挑战的核心概念与背景\", \"情境模拟：实时渲染中的性能优化挑战的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"情境模拟：实时渲染中的性能优化挑战的核心概念与背景\", \"情境模拟：实时渲染中的性能优化挑战的关键方法与执行要点\", \"情境模拟：实时渲染中的性能优化挑战的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 02:23:20', '2026-03-08 02:23:20', 'role_play_scenario', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1e9d6a96-9c72-4c5a-8d78-f75b3716ae61', '9cc0664b-b52b-47ec-82ba-30d9e5a46b2c', 2, '第三部分：数据分析与风险评估', '{\"part\": \"第三部分：数据分析与风险评估\", \"pages\": [{\"title\": \"测试结果统计与质量评估\", \"points\": [\"对比计划与实际执行的用例通过率，分析偏差原因\", \"基于缺陷密度与修复周期评估整体发布风险等级\", \"生成可视化质量仪表盘，展示各模块测试覆盖度分布\", \"明确质量门禁达成情况，给出是否准予上线的决策依据\"]}, {\"title\": \"遗留问题与风险评估\", \"points\": [\"详细列出未修复的低优先级缺陷清单及其当前状态\", \"量化评估遗留问题对系统稳定性及用户体验的具体影响\", \"制定针对高风险遗留项的临时规避方案与监控策略\", \"明确上线后的回滚触发条件与应急处理预案\"]}, {\"title\": \"总结与答疑\", \"points\": [\"核心结论：测试范围、策略规划与质量责任的关键认知\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"]}]}', '{\"text\": \"页面标题：测试结果统计、遗留风险评估与总结答疑\\n\\n页面文字：\\n- 对比计划与实际用例通过率，基于缺陷密度评估整体发布风险等级并生成可视化质量仪表盘。\\n- 详细列出低优先级缺陷清单，量化其对系统稳定性影响并制定上线后回滚触发条件与预案。\\n- 明确质量门禁达成情况作为准予上线决策依据，同时开放答疑探讨后续落地与效果评估方向。\", \"generated_at\": \"2026-03-09T03:10:50.048503\"}', '9cc0664b-b52b-47ec-82ba-30d9e5a46b2c/pages/1e9d6a96-9c72-4c5a-8d78-f75b3716ae61_v1.png', 'COMPLETED', '2026-03-09 03:10:22', '2026-03-09 03:14:13', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('1f282c1d-b2e3-40dc-af03-17640d63cc2a', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 9, NULL, '{\"page_id\": \"p07\", \"title\": \"标准建模全流程逻辑\", \"layout_id\": \"edu_logic_flow\", \"has_image\": true, \"keywords\": [\"标准建模全流程逻辑\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p06\"], \"must_cover\": [\"白模阶段\", \"高模细节\", \"低模优化\", \"标准建模全流程逻辑的核心概念与背景\", \"标准建模全流程逻辑的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_practice_1\"], \"points\": [\"标准建模全流程逻辑的核心概念与背景\", \"标准建模全流程逻辑的关键方法与执行要点\", \"标准建模全流程逻辑的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_practice_1\"], \"logical_page_id\": \"p10\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_flow\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227761\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_logic_flow', '{\"title\": \"标准建模全流程逻辑\", \"subtitle\": \"标准化驱动下的工程级交付路径。\", \"steps\": [{\"number\": 1, \"label\": \"白模构建\", \"description\": \"确立基础拓扑与比例，为后续加工提供准确框架。\", \"icon\": \"fa-cubes\"}, {\"number\": 2, \"label\": \"高模细节\", \"description\": \"雕刻表面凹凸纹理，增强视觉表现的丰富度与真实感。\", \"icon\": \"fa-fingerprint\"}, {\"number\": 3, \"label\": \"低模优化\", \"description\": \"重绘拓扑精简面数，确保引擎中高效流转与实时渲染。\", \"icon\": \"fa-compress-arrows-alt\"}], \"image\": {\"src\": \"\", \"alt\": \"深夜蓝底色的三维流程箭头示意图，展示从白模到高模再到低模的演进关系\", \"width\": \"50%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"process_flow\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('20dbbf4d-b8d3-497c-af9a-013082da2a26', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 6, '第三阶段', '{\"page_id\": \"p06\", \"title\": \"爆发前夜：深度学习与ImageNet的胜利\", \"part\": \"第三阶段\", \"points\": [\"2012年AlexNet在ImageNet竞赛中以压倒性优势刷新纪录，宣告深度学习时代来临\", \"GPU并行计算能力的爆发式增长，解决了深层神经网络训练算力不足的瓶颈\", \"卷积神经网络（CNN）成为计算机视觉新标准，推动图像识别准确率突破人类水平\", \"数据驱动范式确立，彻底取代了传统手工特征工程，为NLP等后续领域奠定基石\"]}', '{\"text\": \"页面标题：爆发前夜：深度学习与ImageNet的胜利\\n\\n页面文字：\\n- 2012年AlexNet在ImageNet竞赛中以压倒性优势刷新纪录，宣告深度学习时代正式来临。\\n- GPU并行计算能力的爆发式增长，成功解决了深层神经网络训练算力不足的长期瓶颈。\\n- 卷积神经网络成为计算机视觉新标准，推动图像识别准确率首次全面突破人类水平。\\n- 数据驱动范式彻底取代传统手工特征工程，为自然语言处理等后续领域奠定坚实基石。\", \"generated_at\": \"2026-03-09T08:54:48.599762\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:28', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('20fdcce3-f0dd-4995-88c7-55bccb2d902a', '8f10b0ec-ba8a-41c7-9730-10360d6d560d', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"高频提问与底层逻辑解析\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"操作卡顿原因分析\", \"软件配置优化建议\", \"快捷键映射策略\", \"高频提问与底层逻辑解析的核心概念与背景\", \"高频提问与底层逻辑解析的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p08_1\", \"text\": \"针对上述软硬件配置问题，我们将引入更多实际案例对比分析\", \"must_cover\": [\"低配电脑替代方案\", \"正版与授权区别\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [\"pr_p07_1\"], \"points\": [\"高频提问与底层逻辑解析的核心概念与背景\", \"高频提问与底层逻辑解析的关键方法与执行要点\", \"高频提问与底层逻辑解析的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p07_1\"], \"layout_archetype\": \"qa_session\", \"layout_variant\": \"d\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T07:30:15.651497\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 07:23:27', '2026-03-07 07:30:16', 'edu_qa_case', '{\"title\": \"高频提问与底层逻辑解析\", \"question\": \"为何出现操作卡顿及快捷键配置失效现象\", \"answer\": \"通过硬件资源诊断与软件配置优化重建交互逻辑\", \"analysis\": [{\"title\": \"操作卡顿原因分析\", \"content\": \"后台冗余进程占用了核心 GPU 显存导致延迟\"}, {\"title\": \"快捷键映射策略\", \"content\": \"统一键位定义，移除冲突脚本并启用硬加速\"}], \"conclusion\": \"理解底层资源调度机制可有效规避重复性问题\", \"variant\": \"d\", \"layout_variant\": \"d\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('21d9deb3-71fb-48f3-9325-ee8e6c657944', '7a4f3408-ca73-4a61-998e-174a92497610', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"学程地图：职业能力提升路径\", \"layout_id\": \"agenda_path\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266511\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'agenda_path', '{\"title\": \"学程地图：职业能力提升路径\", \"items\": [{\"index\": 1, \"text\": \"阶段一：软件界面熟悉与基础操作。\"}, {\"index\": 2, \"text\": \"阶段二：复杂几何体组合与编辑。\"}, {\"index\": 3, \"text\": \"阶段三：UV展开与纹理绘制技巧。\"}, {\"index\": 4, \"text\": \"阶段四：最终渲染与项目交付规范。\"}, {\"index\": 5, \"text\": \"阶段五：行业案例复盘与作品集制作。\"}], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('22d20093-398c-4af9-a587-e51fa57c680c', '14c0f24c-10e7-4309-a927-d9db1066897c', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"标本特写：布线错误与修复案例\", \"layout_id\": \"specimen_detail\", \"has_image\": true, \"keywords\": [\"三角面撕裂特写\", \"极点聚集显微图\", \"修复后平滑对比\", \"极致细节\", \"学术风格\"], \"depends_on\": [\"p06\"], \"must_cover\": [\"N-gon危害\", \"布线断裂原因\", \"拓扑修复方案\", \"标本特写：布线错误与修复案例的核心概念与背景\", \"标本特写：布线错误与修复案例的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"标本特写：布线错误与修复案例的核心概念与背景\", \"标本特写：布线错误与修复案例的关键方法与执行要点\", \"标本特写：布线错误与修复案例的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773833\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'specimen_detail', '{\"title\": \"细节标注：布线错误与修复案例\", \"image_src\": \"https://images.unsplash.com/photo-1542385157-6e9b2d4a2f8e?q=80&w=1200&auto=format&fit=crop\", \"annotations\": [{\"x\": 35, \"y\": 45, \"label\": \"三角面撕裂特写\", \"description\": \"高倍放大下可见非四边面导致的网格拉伸与光影畸变，此为拓扑断裂的微观表现。\"}, {\"x\": 60, \"y\": 30, \"label\": \"极点聚集显微图\", \"description\": \"多边形汇聚点密度异常，显示布线逻辑混乱引发的计算压力集中区。\"}, {\"x\": 20, \"y\": 70, \"label\": \"修复后平滑对比\", \"description\": \"重绘后的均匀四边面流形结构，消除褶皱并恢复模型表面物理模拟的稳定性。\"}], \"background_image\": \"https://images.unsplash.com/photo-1550684848-fac1c5b4e853?q=80&w=1200&auto=format&fit=crop\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('248a107a-b632-4594-81d9-f8f978761655', '6c250523-422a-46f3-a1f1-42e82424897c', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"常见问题与边界条件探讨\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p15\"], \"must_cover\": [\"破面修复\", \"自相交问题\", \"法线翻转\", \"计算溢出\", \"常见问题与边界条件探讨的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"常见问题与边界条件探讨的核心概念与背景\", \"常见问题与边界条件探讨的关键方法与执行要点\", \"常见问题与边界条件探讨的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p19\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287165\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'theory_explanation', '{\"title\": \"常见问题与边界条件探讨\", \"subtitle\": \"破面修复、自相交与数值稳定性分析。\", \"theory\": [\"在几何处理流程中，破面修复是确保模型水密性的关键步骤。当网格存在非流形边或孔洞时，需通过拓扑重建算法自动闭合表面，防止渲染引擎出现穿透或光照异常。此过程要求保持原始曲率特征的同时消除几何缺陷。\", \"自相交问题常发生于高细分网格或变形动画过程中，导致法线方向混乱与渲染伪影。解决策略包括空间分割树（BVH）加速检测与局部翻转修正。同时，法线翻转需结合平滑组设置，确保光影过渡自然，避免硬边突兀。\", \"计算溢出是浮点运算中的潜在风险，尤其在坐标值过大或缩放比例极端时。建议采用归一化坐标系处理中间数据，并限制最大迭代次数以防止算法发散。边界条件的严格定义能有效提升求解器的鲁棒性。\"], \"formulas\": [{\"latex\": \"\\\\mathbf{n}_{new} = \\\\frac{\\\\sum (\\\\mathbf{v}_i - \\\\mathbf{c})}{\\\\|\\\\sum (\\\\mathbf{v}_i - \\\\mathbf{c})\\\\|}\", \"explanation\": \"新法向量计算：基于顶点位置与质心差值的归一化求和，用于修正自相交导致的法线错误。\"}, {\"latex\": \"\\\\text{Error} = \\\\max(|x_i|, |y_i|, |z_i|) > \\\\epsilon_{threshold}\", \"explanation\": \"溢出检测阈值：当坐标分量绝对值超过设定阈值时触发警告或重缩放机制。\"}], \"references\": [\"Wang, Y., & Zhang, L. (2023). Robust Mesh Repairing Techniques in Real-time Rendering. ACM Transactions on Graphics.\", \"Botsch, M., et al. (2022). Geometric Modeling and Processing: Theory and Practice. Springer.\"], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
