INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2bbabb0e-865d-4bf0-8550-ae6f2f71a9a9', '766dd313-1e7e-43f8-b4e9-3ca4b9e71dd6', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"初学者常见问答案例\", \"layout_id\": \"edu_qa_case\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p07\"], \"must_cover\": [\"报错处理逻辑\", \"文件保存格式\", \"代理缩放问题\", \"初学者常见问答案例的核心概念与背景\", \"初学者常见问答案例的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p08_1\", \"text\": \"进阶模型复杂度控制方法\", \"must_cover\": [\"减面技术\", \"法线烘焙\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"初学者常见问答案例的核心概念与背景\", \"初学者常见问答案例的关键方法与执行要点\", \"初学者常见问答案例的应用场景与注意事项\"], \"required_close_promise_ids\": []}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-06 09:45:17', '2026-03-06 09:45:17', 'edu_qa_case', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2c08320b-e9aa-458f-96ed-ab90e1dd338f', '6c250523-422a-46f3-a1f1-42e82424897c', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"理论讲解：多边形建模的数学原理\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p05\"], \"must_cover\": [\"贝塞尔曲线原理\", \"NURBS曲面方程\", \"细分算法简述\", \"理论讲解：多边形建模的数学原理的核心概念与背景\", \"理论讲解：多边形建模的数学原理的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"理论讲解：多边形建模的数学原理的核心概念与背景\", \"理论讲解：多边形建模的数学原理的关键方法与执行要点\", \"理论讲解：多边形建模的数学原理的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286825\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'theory_explanation', '{\"title\": \"理论推导\", \"theory\": [\"多边形建模的数学基础源于离散几何与微分几何的近似。贝塞尔曲线通过控制点定义的参数方程生成平滑轨迹，其凸包性质保证了曲线的可控性。NURBS（非均匀有理B样条）则引入权重因子，能够精确描述圆锥曲线及自由曲面，是工业级高精度建模的核心算法。\", \"细分算法（Subdivision Surface）通过递归分割面片并计算新顶点位置来逼近光滑曲面。Catmull-Clark算法针对四边形网格，而Loop算法针对三角形网格，两者均基于局部加权平均原理，确保在无限细分极限下达到C1或C2连续的光滑度。\"], \"formulas\": [{\"latex\": \"\\\\vec{P}(t) = \\\\sum_{i=0}^{n} B_{i,n}(t) \\\\cdot \\\\vec{P}_i\", \"explanation\": \"贝塞尔曲线定义：\\\\vec{P}(t)为曲线上点，\\\\vec{P}_i为控制点，B_{i,n}(t)为伯恩斯坦基函数。\"}, {\"latex\": \"S = \\\\frac{1}{4} \\\\sum_{k=0}^{3} V_k + \\\\frac{1}{2} \\\\sum_{k=0}^{3} (V_k - M_k)\", \"explanation\": \"Catmull-Clark细分规则简述：新顶点位置由周围顶点的加权平均与中点修正项共同决定。\"}], \"references\": [\"Piegl, L., & Tiller, W. (1997). The NURBS Book.\", \"Zorin, D., Schröder, P., & Sweldens, W. (1996). Interpolating Subdivision Surfaces.\"], \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('2f918c61-37d3-4918-b0e2-cab13c404828', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 7, '第四阶段', '{\"page_id\": \"p07\", \"title\": \"大模型时代：Transformer架构与生成式AI\", \"part\": \"第四阶段\", \"points\": [\"Transformer引入自注意力机制，突破RNN序列限制，实现高效并行计算\", \"GPT系列与大语言模型（LLM）通过海量预训练展现卓越泛化与推理能力\", \"AIGC技术推动AI从被动分析向主动内容创作跨越，重塑内容生产范式\", \"多模态融合成为趋势，文本、图像与音频在统一架构下协同处理\"]}', '{\"text\": \"页面标题：大模型时代：Transformer架构与生成式AI\\n\\n页面文字：\\n- Transformer引入自注意力机制，突破RNN序列限制，实现了高效的并行计算能力。\\n- GPT系列与大语言模型通过海量预训练，展现出卓越的泛化能力与复杂推理水平。\\n- AIGC技术推动AI从被动分析向主动内容创作跨越，彻底重塑了全球内容生产范式。\\n- 多模态融合成为核心趋势，文本、图像与音频在统一架构下实现高效协同处理。\"}', 'a4eba850-5434-409c-bcf0-b43c6ff24364/pages/2f918c61-37d3-4918-b0e2-cab13c404828_v1.png', 'COMPLETED', '2026-03-09 08:54:29', '2026-03-09 08:55:36', NULL, NULL);
