INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4a9ee1e3-f521-4053-9d60-4f6f5d0c0d12', '7823309a-e50c-44f7-9823-bf26169886ac', 3, '第四部分：综合案例分析与总结', '{\"part\": \"第四部分：综合案例分析与总结\", \"pages\": [{\"title\": \"第三章：综合案例分析——精密零件建模\", \"points\": [\"案例背景：某关键工业零部件需求\", \"国产替代意义：技术自主可控实践\", \"精度要求：微米级公差控制标准\", \"全流程演示：从草图到成品拆解\"]}, {\"title\": \"案例复盘：从草图到实体的精准构建\", \"points\": [\"尺寸约束逻辑：参数化驱动设计\", \"特征树管理：历史编辑与版本控制\", \"公差配合：装配体间隙计算\", \"工艺可行性：可制造性分析反馈\"]}, {\"title\": \"案例启示：大国工匠的精度追求\", \"points\": [\"毫厘之间的差距：误差对性能的影响\", \"质量即生命：工匠精神的核心体现\", \"自主创新的决心：突破技术封锁的勇气\", \"职业荣誉感：以作品致敬时代\"]}, {\"title\": \"技术小结：避坑指南与绝活分享\", \"points\": [\"高频错误复盘：新手易踩陷阱汇总\", \"高效工作流：资深设计师的快捷技巧\", \"资源推荐：官方文档与开源社区链接\"]}, {\"title\": \"成果交付：自我评价表与互评标准\", \"points\": [\"完成度自评：模型完整性检查\", \"规范性检查：布线与命名合规性\", \"创新性评价：设计思路的独特性\", \"团队协作反馈：沟通与协作表现\"]}, {\"title\": \"实训总结：回顾与展望\", \"points\": [\"核心知识点回顾：从原理到实战闭环\", \"技能成长路径：后续进阶方向建议\", \"未来应用展望：行业融合发展趋势\"]}], \"logical_page_id\": \"p04\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_id\": \"title_content\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:23:43.630543\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:23:03', '2026-03-08 06:23:44', 'title_content', '{\"title\": \"标准作业：龙骨精准安装与固定\", \"content\": [\"依据三维基准坐标系，将铝合金主龙骨沿放线位置就位，使用专用连接件进行初步卡接，确保节点受力传递路径准确无误。\", \"采用激光水平仪复核龙骨水平度与垂直度，微调至毫米级公差范围内后，按规范扭矩值紧固自攻螺钉，完成刚性连接固定。\"], \"highlight\": \"严禁强行敲击校正偏差，必须通过调节垫片或重新定位解决。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4bbc8b6d-2779-41cb-b5ce-b09c21bec108', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"优化之道：提前终止机制\", \"layout_id\": \"field_observation\", \"has_image\": true, \"keywords\": [\"修复前混乱数据\", \"修复后有序数据\", \"左右分屏对比\", \"修缮前后视觉差\", \"工业实操感\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"标志位flag的作用\", \"已排序区间的识别\", \"优化之道：提前终止机制的核心概念与背景\", \"优化之道：提前终止机制的关键方法与执行要点\", \"优化之道：提前终止机制的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"优化之道：提前终止机制的核心概念与背景\", \"优化之道：提前终止机制的关键方法与执行要点\", \"优化之道：提前终止机制的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832250\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'field_observation', '{\"title\": \"优化之道：标志位驱动的提前终止\", \"image_src\": \"https://example.com/images/sort-refinement-comparison.jpg\", \"image_alt\": \"左右分屏对比图：左侧展示修复前混乱无序的数据流，右侧展示修复后有序且标记已排序区间的稳定状态\", \"caption\": \"图 3.2 修缮前后的视觉与逻辑差异：左图呈现原始版冒泡排序在无序数据中的无效遍历（红色高亮），右图展示引入标志位 flag 后，一旦检测到无交换即立即终止的优化效果（绿色标识）；通过工业实操感的对比，彰显对已排序区间识别的关键价值。\", \"background_image\": \"https://example.com/images/workshop-bg-texture.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4bd0666d-69dc-4322-b18f-6f90cd7e4df5', '14c0f24c-10e7-4309-a927-d9db1066897c', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"第四章：资产整合与行业应用\", \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"引擎导入规范\", \"游戏/影视区别\", \"第四章：资产整合与行业应用的核心概念与背景\", \"第四章：资产整合与行业应用的关键方法与执行要点\", \"第四章：资产整合与行业应用的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第四章：资产整合与行业应用的核心概念与背景\", \"第四章：资产整合与行业应用的关键方法与执行要点\", \"第四章：资产整合与行业应用的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.774090\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'case_before_after', '{\"title\": \"第四章：资产整合与行业应用\", \"left\": {\"header\": \"核心概念与背景\", \"content\": [\"资产整合是连接高精度建模与实时引擎的桥梁，旨在解决影视级细节与游戏性能之间的平衡难题。\"], \"bullets\": [{\"icon\": \"fa-cogs\", \"text\": \"建立统一的引擎导入规范，确保数据流转的标准化与高效性。\", \"description\": \"解释建立统一的引擎导入规范，确保数据流转的标准化与高效性。在核心概念与背景维度下的意义。\"}, {\"icon\": \"fa-gamepad\", \"text\": \"明确游戏与影视在渲染管线、多边形预算及材质通道上的本质区别。\", \"description\": \"解释明确游戏与影视在渲染管线、多边形预算及材质通道上的本质区别。在核心概念与背景维度下的意义。\"}]}, \"right\": {\"header\": \"关键方法与执行要点\", \"content\": [\"通过差异化的优化策略，将高模资产转化为符合实时运行标准的低模资源。\", \"结论：第四章：资产整合与行业应用需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-project-diagram\", \"text\": \"制定严格的命名规范与层级结构，避免场景加载时的资源冲突。\", \"description\": \"解释制定严格的命名规范与层级结构，避免场景加载时的资源冲突。在关键方法与执行要点维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"根据应用场景动态调整贴图分辨率与光照烘焙质量，实现视觉与性能的平衡。\", \"description\": \"解释根据应用场景动态调整贴图分辨率与光照烘焙质量，实现视觉与性能的平衡。在关键方法与执行要点维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
