INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4ecfc8a9-65a2-4b60-9a23-c528a5c1dba1', '2210a36d-b61a-453a-83ee-86edc9925e6a', 0, NULL, '{\"page_id\": \"p01\", \"title\": \"3D 建模基础与流程指南\", \"layout_id\": \"cover_academic\", \"has_image\": true, \"keywords\": [\"石板蓝背景\", \"冷灰色网格纹理\", \"金棕色几何装饰\", \"学术风格封面\"], \"depends_on\": [], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"logical_page_id\": \"p01\", \"layout_variant\": \"a\", \"layout_archetype\": \"cover\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647514\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'cover_academic', '{\"title\": \"3D 建模基础与流程指南\", \"subtitle\": \"系统化理论与实务操作。\", \"author\": \"资深讲师团队\", \"department\": \"计算机图形学教研室\", \"date\": \"2024 年 5 月 20 日\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"cover\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4ef3012e-2694-4d32-8545-7965e5aec6e1', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"直观演示：气泡如何“冒泡”\", \"layout_id\": \"infographic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"遍历过程\", \"最大值上浮机制\", \"直观演示：气泡如何“冒泡”的核心概念与背景\", \"直观演示：气泡如何“冒泡”的关键方法与执行要点\", \"直观演示：气泡如何“冒泡”的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_p05_1\", \"text\": \"稍后将通过代码实现展示具体逻辑\", \"must_cover\": [\"伪代码\", \"循环结构\"], \"target_page_ids\": [\"p20\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"直观演示：气泡如何“冒泡”的核心概念与背景\", \"直观演示：气泡如何“冒泡”的关键方法与执行要点\", \"直观演示：气泡如何“冒泡”的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.831986\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'infographic_flow', '{\"title\": \"直观演示：气泡如何“冒泡”\", \"subtitle\": \"遍历机制与最大值上浮原理。\", \"bullets\": [{\"icon\": \"fa-arrows-alt-h\", \"text\": \"相邻元素两两比较。\", \"description\": \"从序列头部开始，依次比较相邻两个数据的大小，若顺序错误则立即交换位置。\"}, {\"icon\": \"fa-arrow-up\", \"text\": \"大值逐次上浮。\", \"description\": \"经过一轮完整遍历后，当前未排序部分中的最大值必然移动至该轮次的末尾位置。\"}, {\"icon\": \"fa-repeat\", \"text\": \"多轮迭代收敛。\", \"description\": \"重复上述过程，每轮减少一个待排序元素，直至所有数据完成有序排列。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"稳定性保障。\", \"description\": \"仅在严格大于时交换，确保相等元素的相对顺序保持不变。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"渐进式有序化。\", \"description\": \"数据从无序到有序是一个平滑过渡的物理过程，而非突变。\"}], \"keyTakeaway\": \"冒泡排序通过反复的相邻交换，利用“大数下沉、小数上浮”的物理直觉，将无序集合逐步转化为有序序列。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('4f102670-a7fa-405b-8f4b-504c004d18f7', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 15, '收尾', '{\"page_id\": \"p13\", \"title\": \"答疑互动与下一步行动\", \"part\": \"收尾\", \"points\": [\"现场开放提问，针对性解决建模拓扑与渲染报错等具体困惑\", \"发布课后进阶任务清单，涵盖低模硬表面与角色雕刻实战练习\", \"引导加入专属学习社群，获取最新插件资源与行业接单渠道\", \"推荐后续高阶课程路径，规划从入门到职业级建模师的成长路线\"]}', '{\"text\": \"答疑互动与下一步行动\\n\\n页面文字：\\n- 现场开放提问环节，针对性解决建模拓扑错误与渲染报错等具体困惑与技术难题。\\n- 发布课后进阶任务清单，涵盖低模硬表面设计与角色雕刻实战练习以巩固所学。\\n- 引导加入专属学习社群获取最新插件资源与行业接单渠道，拓展职业发展机会。\\n- 推荐后续高阶课程路径，科学规划从入门新手到职业级建模师的完整成长路线。\", \"generated_at\": \"2026-03-09T03:39:42.429944\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/4f102670-a7fa-405b-8f4b-504c004d18f7_v1.png', 'COMPLETED', '2026-03-09 03:39:30', '2026-03-09 03:49:26', NULL, NULL);
