INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('51645ffb-88cd-4313-8543-1fb681dab6e9', '14c0f24c-10e7-4309-a927-d9db1066897c', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"光影对比：不同布光下的情绪差异\", \"layout_id\": \"site_survey\", \"has_image\": true, \"keywords\": [\"三点布光示意\", \"冷色调场景\", \"暖色调场景\", \"全景测绘感\", \"无Logo\"], \"depends_on\": [\"p13\"], \"must_cover\": [\"主光方向\", \"补光作用\", \"情绪表达\", \"光影对比：不同布光下的情绪差异的核心概念与背景\", \"光影对比：不同布光下的情绪差异的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"光影对比：不同布光下的情绪差异的核心概念与背景\", \"光影对比：不同布光下的情绪差异的关键方法与执行要点\", \"光影对比：不同布光下的情绪差异的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p15\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.774054\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'site_survey', '{\"title\": \"光影对比：不同布光下的情绪差异\", \"image_src\": \"https://images.unsplash.com/photo-1542385151-5e8d2f0c0f4a?q=80&w=1200&auto=format&fit=crop\", \"image_alt\": \"同一场景在三点布光下的两种状态对比，左侧冷色调表现冷静科技感，右侧暖色调表现温馨人文感\", \"caption\": \"主光方向决定形态轮廓，补光作用平衡明暗反差。冷调强化理性秩序，暖调激发情感共鸣，布光是无声的导演。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
