INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('52b2d6b3-7711-44b6-add3-f8607a54edc6', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"即时反馈：你遇到的最大渲染瓶颈是什么？\", \"layout_id\": \"feedback_poll\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p16\"], \"must_cover\": [\"实时投票收集\", \"痛点分类统计\", \"针对性解决方案预告\", \"即时反馈：你遇到的最大渲染瓶颈是什么？的核心概念与背景\", \"即时反馈：你遇到的最大渲染瓶颈是什么？的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"即时反馈：你遇到的最大渲染瓶颈是什么？的核心概念与背景\", \"即时反馈：你遇到的最大渲染瓶颈是什么？的关键方法与执行要点\", \"即时反馈：你遇到的最大渲染瓶颈是什么？的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928819\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'feedback_poll', '{\"title\": \"即时反馈：你遇到的最大渲染瓶颈是什么？\", \"content\": [\"在高效的工作流中，渲染瓶颈往往决定了项目的最终交付质量。请思考并选择您目前面临的最大挑战：是计算资源不足、光照噪点过多，还是材质表现力受限？\", \"我们将根据您的投票结果，在下个环节针对性地提供优化方案，帮助大家突破技术卡点，提升渲染效率与画面表现。\"], \"highlight\": \"识别瓶颈，方能精准破局\", \"image\": {\"src\": \"\", \"alt\": \"三个互动气泡图标悬浮于进度环旁，分别代表算力、噪点和材质，背景为澄净青色网络结构\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
