INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('55c04fde-8523-40fb-80d3-655342fce0ab', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"实战演练：不同场景下的选择\", \"layout_id\": \"portfolio_industry\", \"has_image\": true, \"keywords\": [\"优秀算法作品陈列\", \"多种排序结果展示\", \"专业作品集风格\", \"高清图集\", \"稳重色调\"], \"depends_on\": [\"p12\"], \"must_cover\": [\"小数据集适用性\", \"稳定性要求场景\", \"实战演练：不同场景下的选择的核心概念与背景\", \"实战演练：不同场景下的选择的关键方法与执行要点\", \"实战演练：不同场景下的选择的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"实战演练：不同场景下的选择的核心概念与背景\", \"实战演练：不同场景下的选择的关键方法与执行要点\", \"实战演练：不同场景下的选择的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832290\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'portfolio_industry', '{\"title\": \"作品展示：多场景排序实战\", \"subtitle\": \"从小数据集到稳定性要求的工业级算法陈列。\", \"items\": [{\"image_src\": \"https://example.com/images/sort-workshop-grid-01.jpg\", \"title\": \"小数据集高效排序\", \"description\": \"针对百条以内数据的快速响应方案，展示插入排序与优化后冒泡排序的对比效果，体现低延迟特性。\", \"tags\": [\"小数据量\", \"低延迟\", \"即时反馈\"]}, {\"image_src\": \"https://example.com/images/sort-workshop-grid-02.jpg\", \"title\": \"高稳定性要求场景\", \"description\": \"金融交易记录等对顺序敏感的场景，通过标志位驱动的提前终止机制，确保相同元素相对位置不变。\", \"tags\": [\"数据稳定\", \"金融级\", \"零扰动\"]}, {\"image_src\": \"https://example.com/images/sort-workshop-grid-03.jpg\", \"title\": \"复杂逻辑下的执行流\", \"description\": \"可视化展示嵌套循环中的比较次数热力分布，直观呈现 O(n²) 在极端情况下的资源消耗与优化空间。\", \"tags\": [\"复杂度分析\", \"热力图\", \"性能瓶颈\"]}], \"layout\": \"grid\", \"background_image\": \"https://example.com/images/archival-bg-neutral.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('561d8dab-4e58-4a97-b899-d50c9cc23ac1', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 6, NULL, '{\"page_id\": \"p07\", \"title\": \"案例研讨：角色关节处的布线策略\", \"layout_id\": \"case_discussion\", \"has_image\": true, \"keywords\": [\"角色手臂关节解剖图\", \"环形布线示意图\", \"小组讨论引导卡片\", \"工业实操感\", \"橙色重点标记\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"肘部/膝盖环形结构\", \"肌肉走向模拟\", \"折叠与拉伸测试\", \"案例研讨：角色关节处的布线策略的核心概念与背景\", \"案例研讨：角色关节处的布线策略的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_case_01\", \"text\": \"稍后展示该案例的最终动画测试效果\", \"must_cover\": [\"动画测试结果\", \"常见问题复盘\"], \"target_page_ids\": [\"p19\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"案例研讨：角色关节处的布线策略的核心概念与背景\", \"案例研讨：角色关节处的布线策略的关键方法与执行要点\", \"案例研讨：角色关节处的布线策略的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p07\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928384\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'case_discussion', '{\"title\": \"案例研讨：角色关节处的布线策略\", \"content\": [\"在工业级角色动画中，肘部与膝盖的变形是检验拓扑质量的关键试金石。若布线未遵循肌肉走向形成环形结构，模型在弯曲时极易出现非预期的褶皱或拉伸撕裂。\", \"本案例聚焦于构建完美的“支撑环”系统，通过模拟真实解剖结构，确保网格在极限折叠与拉伸测试中保持平滑过渡，避免三角面导致的硬边缺陷。\"], \"highlight\": \"环形布线是关节变形的生命线，必须严格匹配肌肉收缩方向。\", \"image\": {\"src\": \"\", \"alt\": \"角色手臂关节解剖图与环形布线示意图，橙色重点标记关键支撑环位置，展示折叠与拉伸测试效果\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('56adcc1c-f032-4537-ac05-d6d07681454a', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 10, '实战演练', '{\"page_id\": \"p09\", \"title\": \"综合案例：现代家居场景搭建\", \"part\": \"实战演练\", \"points\": [\"利用参数化组件库实现沙发、灯具等家具的快速模块化组装与复用\", \"基于人体工学设定空间尺度，运用三分法与引导线优化视觉构图\", \"从基础白模布线到材质赋予、灯光布置及最终渲染输出的全流程复盘\", \"针对室内环境的光影反射特性进行细节调试，提升场景真实感\"]}', '{\"text\": \"页面标题：综合案例：现代家居场景搭建\\n\\n页面文字：\\n- 面对复杂家具组装难题，利用参数化组件库实现沙发灯具的快速模块化复用与搭建。\\n- 基于人体工学设定空间尺度，运用三分法构图引导视线，优化整体视觉平衡关系。\\n- 从白模布线到材质赋予及灯光调试的全流程复盘，成功解决室内光影反射细节问题。\\n- 最终通过精细调试大幅提升场景真实感，为后续硬表面建模实战打下坚实基础。\", \"generated_at\": \"2026-03-09T03:39:38.191762\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/56adcc1c-f032-4537-ac05-d6d07681454a_v1.png', 'COMPLETED', '2026-03-09 03:39:22', '2026-03-09 03:47:53', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('580c9105-55a4-4263-92bf-db99f3ddece1', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"双重循环的逻辑拆解\", \"layout_id\": \"site_survey\", \"has_image\": true, \"keywords\": [\"左侧代码高亮\", \"右侧流程图对应\", \"对比色块\", \"技术文档风格\", \"清晰排版\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"外层控制轮次\", \"内层控制比较\", \"双重循环的逻辑拆解的核心概念与背景\", \"双重循环的逻辑拆解的关键方法与执行要点\", \"双重循环的逻辑拆解的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p05_1\", \"pr_p07_1\"], \"points\": [\"双重循环的逻辑拆解的核心概念与背景\", \"双重循环的逻辑拆解的关键方法与执行要点\", \"双重循环的逻辑拆解的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p05_1\", \"pr_p07_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p05_1\", \"pr_p07_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832103\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'site_survey', '{\"title\": \"双重循环的逻辑拆解：内外协同\", \"image_src\": \"https://example.com/images/code-flow-diagram.jpg\", \"image_alt\": \"左侧为高亮显示的嵌套循环代码片段，右侧为对应的黑白流程图，通过对比色块清晰展示外层控制变量 i 与内层控制变量 j 的层级关系及数据流向。\", \"caption\": \"图 2.2 双重循环逻辑全景：左侧代码精准对应右侧流程，红色高亮区分控制轮次（外层）与比较动作（内层），直观呈现算法运行的微观秩序。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('586d24b4-f440-4146-b540-4c8bf13b32bc', '6c250523-422a-46f3-a1f1-42e82424897c', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"进阶技巧：雕刻与细节塑造\", \"layout_id\": \"academic_narrative\", \"has_image\": true, \"keywords\": [\"数字雕刻\", \"笔刷效果\", \"肌肉纹理\", \"岩石质感\", \"高精度模型\"], \"depends_on\": [\"p14\"], \"must_cover\": [\"动态拓扑\", \"细节层次\", \"平滑组设置\", \"法线叠加\", \"进阶技巧：雕刻与细节塑造的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"进阶技巧：雕刻与细节塑造的核心概念与背景\", \"进阶技巧：雕刻与细节塑造的关键方法与执行要点\", \"进阶技巧：雕刻与细节塑造的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287133\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_narrative', '{\"title\": \"进阶技巧：雕刻与细节塑造\", \"narrative\": [\"数字雕刻打破了传统多边形建模的拓扑限制，允许艺术家直接在虚拟粘土上创作，通过笔刷模拟真实物理质感。该技术核心在于动态拓扑（Dynamic Topology），系统根据笔触压力自动细分网格，实现从宏观形体到微观毛孔的多层次细节塑造，广泛应用于角色肌肉纹理、岩石风化痕迹等高精度资产制作。\", \"在细节深化阶段，平滑组（Smoothing Groups）的设置决定了光影过渡的自然度，而法线叠加（Normal Blending）则用于融合不同笔触产生的细微起伏。通过分层雕刻策略，先确立大体积结构，再逐步添加次级细节，最后进行微调，确保模型在高分辨率下依然保持结构清晰，避免细节杂乱无章。\", \"应用实践中，需注意雕刻深度与游戏引擎性能的平衡。虽然高精度模型能呈现极致细节，但需通过置换烘焙将其转化为低模可用的贴图数据。风险提示包括过度细分导致的内存溢出，以及缺乏整体构图意识造成的局部过度修饰，建议在雕刻前制定明确的细节层级规划。\"], \"margin_notes\": [{\"title\": \"核心概念：动态拓扑\", \"content\": \"一种实时细分算法，仅在笔触作用区域增加多边形数量，无需预先规划布线，极大提升了自由创作的灵活性。\"}, {\"title\": \"细节层级（LOD）\", \"content\": \"雕刻时需考虑不同观察距离下的细节表现，远观看大形，近观看细节，避免无效的高频噪声。\"}], \"pull_quote\": \"雕刻不仅是形状的塑造，更是对光影关系的预判；每一笔落下，都是在定义光线如何在曲面上流动。\", \"background_image\": \"\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('588ef5d1-3cf2-44d6-97cc-a54f7c8c58ad', '9b5d83ef-2600-4c3b-b852-00607680277d', 12, '总结', '{\"page_id\": \"p11\", \"title\": \"核心回顾：发展脉络与关键节点\", \"part\": \"总结\", \"points\": [\"ChatGPT引爆大众认知，Claude确立安全与长文本标杆，Gemini实现多模态原生融合\", \"技术演进从单一对话交互跨越至复杂逻辑推理与全感官理解的新阶段\", \"未来竞争焦点将聚焦于模型对齐的可靠性与推理成本的极致优化\"]}', '{\"text\": \"核心回顾：发展脉络与关键节点\\n\\n页面文字：\\n- ChatGPT引爆大众认知，Claude确立安全与长文本标杆，Gemini实现多模态原生融合。\\n- 技术演进从单一对话交互跨越至复杂逻辑推理与全感官理解的新阶段。\\n- 未来竞争焦点将聚焦于模型对齐的可靠性与推理成本的极致优化。\", \"generated_at\": \"2026-03-09T08:14:14.372588\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/588ef5d1-3cf2-44d6-97cc-a54f7c8c58ad_v1.png', 'FAILED', '2026-03-09 08:13:57', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('599b37c5-3331-46e0-ad0d-9839f7e46f86', '7a4f3408-ca73-4a61-998e-174a92497610', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"第二章：硬表面与有机体建模策略\", \"layout_id\": \"warmup_inquiry\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"硬表面建模特点\", \"生物体建模难点\", \"本章实战任务\", \"第二章：硬表面与有机体建模策略的核心概念与背景\", \"第二章：硬表面与有机体建模策略的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p07_1\", \"text\": \"通过协作任务完成一款机械零件的建模\", \"must_cover\": [\"分块思路\", \"细节刻画\", \"倒角处理\"], \"target_page_ids\": [\"p17\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"第二章：硬表面与有机体建模策略的核心概念与背景\", \"第二章：硬表面与有机体建模策略的关键方法与执行要点\", \"第二章：硬表面与有机体建模策略的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266707\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'warmup_inquiry', '{\"question\": \"面对精密工业零件与生物有机体两种截然不同的对象，你认为在布线策略与拓扑构建上最本质的区别是什么？\", \"thinkTime\": 30, \"hints\": [\"思考硬表面如何依赖循环边维持锐利转折与平整度\", \"分析有机体为何需要遵循肌肉走向进行环形布线以支持变形\"], \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('59b170ce-15f5-42d7-b443-cdc886bb39f5', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 21, NULL, '{\"page_id\": \"p16\", \"title\": \"常见问题与疑难解答\", \"layout_id\": \"edu_qa_case\", \"has_image\": true, \"keywords\": [\"警示感叹号图标\", \"故障代码块样式\", \"深色调试窗口\"], \"depends_on\": [\"p15\"], \"must_cover\": [\"布线错误修复\", \"法线反转处理\", \"常见问题与疑难解答的核心概念与背景\", \"常见问题与疑难解答的关键方法与执行要点\", \"常见问题与疑难解答的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"常见问题与疑难解答的核心概念与背景\", \"常见问题与疑难解答的关键方法与执行要点\", \"常见问题与疑难解答的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p22\", \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T12:17:13.187685\"}', NULL, 'FAILED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_qa_case', '{\"title\": \"常见问题与疑难解答\", \"question\": \"场景渲染出现黑面或布线报错如何快速定位？\", \"answer\": \"检查法线方向确保一致，使用拓扑诊断插件一键修复异常网格。\", \"analysis\": [{\"title\": \"拓扑规范\", \"content\": \"保持四边形分布，消除三角面死角，防止细分后形变。\"}, {\"title\": \"光影设置\", \"content\": \"验证灯光衰减参数，开启背面剔除功能测试阴影深度。\"}], \"conclusion\": \"完善交付前自检清单，降低沟通返工成本。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('59c9f12f-b1cd-43e8-8ac6-eae8c9f4d1bb', '9b5d83ef-2600-4c3b-b852-00607680277d', 2, 'ChatGPT篇', '{\"page_id\": \"p03\", \"title\": \"里程碑一：ChatGPT引爆大众认知\", \"part\": \"ChatGPT篇\", \"points\": [\"2022年11月横空出世，首创RLHF技术让对话从机械回复进化为自然交互\", \"突破传统NLP规则限制，以零样本学习能力开启AIGC全民应用新纪元\", \"单月用户破亿刷新历史纪录，引发全球对通用人工智能（AGI）的热烈探讨\", \"重塑人机协作模式，将生成式AI从实验室研究推向大众日常生活\"]}', '{\"text\": \"页面标题：里程碑一：ChatGPT引爆大众认知\\n\\n页面文字：\\n- 2022年11月横空出世，首创RLHF技术让对话从机械回复进化为自然交互体验。\\n- 突破传统NLP规则限制，以零样本学习能力开启AIGC全民应用新纪元。\\n- 单月用户破亿刷新历史纪录，引发全球对通用人工智能（AGI）的热烈探讨。\\n- 重塑人机协作模式，将生成式AI从实验室研究推向大众日常生活。\", \"generated_at\": \"2026-03-09T08:14:14.359473\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/59c9f12f-b1cd-43e8-8ac6-eae8c9f4d1bb_v1.png', 'FAILED', '2026-03-09 08:13:40', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5a02e943-3061-45ca-b0ec-19b559f657bd', '8f10b0ec-ba8a-41c7-9730-10360d6d560d', 1, NULL, '{\"page_id\": \"p02\", \"title\": \"课程架构导览\", \"layout_id\": \"edu_toc\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"b\", \"logical_page_id\": \"p02\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T07:30:15.651327\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 07:23:27', '2026-03-07 07:30:16', 'edu_toc', '{\"title\": \"课程架构导览\", \"subtitle\": \"从基础原理到工业级工作流的全方位解析。\", \"items\": [{\"index\": 1, \"text\": \"基础理论与工具认知。\"}, {\"index\": 2, \"text\": \"多边形建模核心技法。\"}, {\"index\": 3, \"text\": \"NURBS 与参数化设计。\"}, {\"index\": 4, \"text\": \"纹理映射与材质系统。\"}, {\"index\": 5, \"text\": \"灯光渲染与后期合成。\"}, {\"index\": 6, \"text\": \"动态仿真与特效制作。\"}], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5add2e6f-127b-47e7-b4de-ad347abecc19', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 1, '导览', '{\"page_id\": \"p02\", \"title\": \"目录：AI发展的四个核心阶段\", \"part\": \"导览\", \"points\": [\"萌芽期：图灵测试与达特茅斯会议奠定理论基石（1950s前）\", \"第一次浪潮：专家系统主导逻辑推理，遭遇知识工程瓶颈（1956-1980）\", \"第二次浪潮：统计学习兴起，大数据驱动算法从规则转向概率（1990-2010）\", \"爆发期：深度学习与大模型重构产业，开启生成式智能新纪元（2012至今）\"]}', '{\"text\": \"页面标题：目录：AI发展的四个核心阶段\\n\\n页面文字：\\n- 萌芽期由图灵测试与达特茅斯会议奠定理论基石，确立了机器思维的哲学基础。\\n- 第一次浪潮以专家系统主导逻辑推理，却因知识工程瓶颈遭遇发展停滞困境。\\n- 第二次浪潮统计学习兴起，大数据驱动算法从规则转向概率解决不确定性问题。\\n- 爆发期深度学习重构产业，开启生成式智能新纪元并推动应用全面落地生根。\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:20', '2026-03-09 16:55:02', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5c004a85-1406-4cd1-ad0c-8cfd78eb54aa', '2210a36d-b61a-453a-83ee-86edc9925e6a', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"全章核心技能复盘\", \"layout_id\": \"key_takeaways\", \"has_image\": true, \"keywords\": [\"全章核心技能复盘\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p14\"], \"must_cover\": [\"全流程知识点串联\", \"课后练习推荐清单\", \"全章核心技能复盘的核心概念与背景\", \"全章核心技能复盘的关键方法与执行要点\", \"全章核心技能复盘的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"全章核心技能复盘的核心概念与背景\", \"全章核心技能复盘的关键方法与执行要点\", \"全章核心技能复盘的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p17\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647803\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 15:18:26', 'key_takeaways', '{\"title\": \"全章核心技能复盘\", \"subtitle\": \"技能应用与实践清单。\", \"bullets\": [{\"icon\": \"fa-sitemap\", \"text\": \"拓扑布线规范。\", \"description\": \"坚持四边形优先，避免 N-gon 导致变形。\"}, {\"icon\": \"fa-memory\", \"text\": \"硬件性能匹配。\", \"description\": \"高显存保纹理质量，大内存防崩溃。\"}, {\"icon\": \"fa-share-alt\", \"text\": \"格式导出标准。\", \"description\": \"统一单位，检查 UV 展开完整性。\"}, {\"icon\": \"fa-code-branch\", \"text\": \"网格错误修复。\", \"description\": \"合并重复点，修复非流形几何体。\"}, {\"icon\": \"fa-tasks\", \"text\": \"课后练习任务。\", \"description\": \"复现案例，记录报错日志。\"}], \"keyTakeaway\": \"构建从建模到优化的完整工作流认知。\", \"image\": {\"src\": \"\", \"alt\": \"技能树状图与硬件配置示意图\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5d0d257a-3206-453c-a054-ac5cd97a7d87', '6c250523-422a-46f3-a1f1-42e82424897c', 21, NULL, '{\"page_id\": \"p22\", \"title\": \"课后思考题与拓展阅读\", \"layout_id\": \"key_concepts\", \"has_image\": true, \"keywords\": [\"课后思考题与拓展阅读\", \"场景示意\", \"视觉辅助\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"场景设计挑战\", \"风格化探索\", \"推荐阅读书目\", \"相关论文\", \"课后思考题与拓展阅读的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课后思考题与拓展阅读的核心概念与背景\", \"课后思考题与拓展阅读的关键方法与执行要点\", \"课后思考题与拓展阅读的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p22\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287330\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 14:27:28', 'key_concepts', '{\"title\": \"课后思考题与拓展阅读\", \"subtitle\": \"深化场景设计挑战与风格化探索。\", \"bullets\": [{\"icon\": \"fa fa-book\", \"text\": \"核心概念回顾：几何处理边界条件。\", \"description\": \"结合前序内容，深入理解破面修复与非流形边处理在确保模型水密性中的关键作用，分析自相交导致的渲染穿透问题。\"}, {\"icon\": \"fa fa-paint-brush\", \"text\": \"风格化探索路径。\", \"description\": \"探讨从UV展开映射到动态雕刻细化的全流程，如何通过置换烘焙实现低模高显，平衡艺术风格与技术性能。\"}, {\"icon\": \"fa fa-cogs\", \"text\": \"场景设计挑战分析。\", \"description\": \"针对复杂场景下的数值稳定性进行分析，研究在极端几何结构下保持网格完整性的最佳实践方案。\"}, {\"icon\": \"fa fa-search\", \"text\": \"推荐阅读书目。\", \"description\": \"《计算机图形学原理与实践》、《实时渲染技术指南》，重点研读关于网格简化与拓扑优化的章节。\"}, {\"icon\": \"fa fa-file-text-o\", \"text\": \"相关论文导读。\", \"description\": \"精选近三年关于非流形几何修复及实时光照稳定性的顶会论文，梳理最新算法演进趋势。\"}], \"keyTakeaway\": \"通过系统梳理几何处理流程中的边界条件与风格化技巧，构建从理论定义到工程落地的完整认知闭环。\", \"image\": {\"src\": \"https://images.unsplash.com/photo-1550684848-fac1c5b4e853?auto=format&fit=crop&w=600&q=80\", \"alt\": \"抽象的学术网格背景与书籍剪影，体现几何结构与知识沉淀\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
