INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5f4f8db0-8763-4df1-9699-f6ac97134064', '9cc0664b-b52b-47ec-82ba-30d9e5a46b2c', 0, '第一部分：策略规划', '{\"part\": \"第一部分：策略规划\", \"pages\": [{\"title\": \"制定自动化回归与手工探索性测试的配比方案，平衡效：重点展开\", \"points\": [\"制定自动化回归与手工探索性测试的配比方案，平衡效的核心概念与边界\", \"制定自动化回归与手工探索性测试的配比方案，平衡效的典型案例与结果\", \"制定自动化回归与手工探索性测试的配比方案，平衡效在本主题中的落地建议\"]}]}', '{\"text\": \"页面标题：制定自动化回归与手工探索性测试的配比方案，平衡效：重点展开\\n\\n页面文字：\\n- 明确自动化回归覆盖稳定核心路径，手工探索聚焦复杂边界场景的核心概念与执行边界。\\n- 分享某金融系统通过70%自动加30%手工策略，将缺陷漏测率降低40%的典型成功案例。\\n- 建议根据版本迭代频率动态调整配比，在快速发布期侧重自动化效率，在新功能期强化手工探索。\", \"generated_at\": \"2026-03-09T03:10:50.048490\"}', '9cc0664b-b52b-47ec-82ba-30d9e5a46b2c/pages/5f4f8db0-8763-4df1-9699-f6ac97134064_v1.png', 'COMPLETED', '2026-03-09 03:10:22', '2026-03-09 03:11:38', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('5f94c8b5-0361-45b9-acb5-f361303c546a', '6c250523-422a-46f3-a1f1-42e82424897c', 22, NULL, '{\"page_id\": \"p23\", \"title\": \"致谢与参考文献\", \"layout_id\": \"ending_academic\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p19\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p23\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287358\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'ending_academic', '{\"title\": \"致谢与参考文献\", \"summary_points\": [\"核心知识点回顾：掌握了从拓扑结构定义、UV展开、动态雕刻到置换烘焙的完整工作流闭环。\", \"关键技能总结：能够独立处理破面修复、自相交等几何边界问题，并应用风格化技巧优化渲染效果。\", \"工具链掌握：熟练运用Unity/Unreal引擎API及Blender/Maya建模软件的最佳实践。\"], \"homework\": [\"作业一：选取一个存在非流形边的模型，使用拓扑重建算法完成修复，并输出修复前后的对比报告。\", \"作业二：设计一个具有特定艺术风格的低模场景，提交包含UV展开图与置换烘焙效果的工程文件。\"], \"next_chapter\": \"下节预告：进阶材质系统与程序化纹理生成技术详解。\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
