INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('64ebb468-3d77-4506-b16e-ef183d52baf1', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 0, '封面', '{\"page_id\": \"p01\", \"title\": \"封面：AI发展史——从图灵测试到智能时代\", \"part\": \"封面\", \"points\": [\"主题：人工智能的演进历程与关键转折\", \"副标题：探索技术爆发的百年轨迹\", \"演讲人：[您的姓名/团队名称]\", \"日期：2023年X月X日\"]}', '{\"text\": \"页面标题：封面：AI发展史——从图灵测试到智能时代\\n\\n页面文字：\\n- 本页面聚焦人工智能的演进历程，梳理其从理论萌芽到关键转折的核心脉络。\\n- 副标题旨在探索技术爆发的百年轨迹，见证机器如何从逻辑模拟迈向自主智能。\\n- 演讲人将带领观众回顾历史节点，展望智能时代带来的产业变革与未来机遇。\", \"generated_at\": \"2026-03-09T08:54:47.422422\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:19', '2026-03-09 08:54:49', NULL, NULL);
