INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6b721ce7-69c3-4b40-b93f-e2bfc29d1afe', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"时间复杂度：O(n^2)的由来\", \"layout_id\": \"site_survey\", \"has_image\": true, \"keywords\": [\"全景数据分布图\", \"局部放大分析\", \"经纬度式坐标轴\", \"工程测绘风\", \"中性色大色块\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"比较次数计算\", \"交换次数上限\", \"时间复杂度：O(n^2)的由来的核心概念与背景\", \"时间复杂度：O(n^2)的由来的关键方法与执行要点\", \"时间复杂度：O(n^2)的由来的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_2\", \"pr_p10_1\"], \"points\": [\"时间复杂度：O(n^2)的由来的核心概念与背景\", \"时间复杂度：O(n^2)的由来的关键方法与执行要点\", \"时间复杂度：O(n^2)的由来的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\", \"pr_p10_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832209\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'site_survey', '{\"title\": \"时间复杂度剖析：O(n²)的几何溯源\", \"image_src\": \"https://example.com/images/complexity-geometric-map.jpg\", \"image_alt\": \"工程测绘风格的全景数据分布图，展示经纬度式坐标轴下的比较次数热力分布\", \"caption\": \"图 3.1 数据规模与操作次数的非线性关系：左侧为全局数据分布，右侧局部放大揭示嵌套循环导致的平方级增长趋势；中性色大色块清晰界定最坏情况下的比较上限与交换频率，直观呈现 O(n²) 的数学本质。\", \"background_image\": \"https://example.com/images/mapping-bg-subtle.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6c306f26-86ee-4b06-b5e9-6ffd60660db4', '14c0f24c-10e7-4309-a927-d9db1066897c', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"成果品鉴：行业级作品赏析\", \"layout_id\": \"portfolio_industry\", \"has_image\": true, \"keywords\": [\"电影级角色特写\", \"宏大场景渲染\", \"高保真材质\", \"画廊陈列风格\"], \"depends_on\": [\"p16\"], \"must_cover\": [\"技术上限展示\", \"艺术风格多样性\", \"成果品鉴：行业级作品赏析的核心概念与背景\", \"成果品鉴：行业级作品赏析的关键方法与执行要点\", \"成果品鉴：行业级作品赏析的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"成果品鉴：行业级作品赏析的核心概念与背景\", \"成果品鉴：行业级作品赏析的关键方法与执行要点\", \"成果品鉴：行业级作品赏析的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.774270\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'portfolio_industry', '{\"title\": \"成果品鉴：行业级作品赏析\", \"subtitle\": \"技术上限展示与艺术风格多样性。\", \"items\": [{\"image_src\": \"https://images.unsplash.com/photo-1635326444826-06c8f8d9e02a?q=80&w=1200&auto=format&fit=crop\", \"title\": \"电影级角色特写\", \"description\": \"基于PBR工作流的高保真角色渲染，展现皮肤次表面散射与微细毛发物理属性，体现光影叙事的情感张力。\", \"tags\": [\"高保真材质\", \"电影级渲染\"]}, {\"image_src\": \"https://images.unsplash.com/photo-1542259685-76d93b746796?q=80&w=1200&auto=format&fit=crop\", \"title\": \"宏大场景构建\", \"description\": \"结合程序化生成与手工雕刻技术的开放世界场景，展示LOD优化与视锥剔除在大规模环境中的应用效果。\", \"tags\": [\"宏大场景\", \"实时优化\"]}, {\"image_src\": \"https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?q=80&w=1200&auto=format&fit=crop\", \"title\": \"工业资产复原\", \"description\": \"从机械零件到复杂装配体的全流程资产整合案例，验证了标准化导入规范与拓扑优化的实际效能。\", \"tags\": [\"工业复原\", \"资产管线\"]}], \"layout\": \"grid\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6c82e9f2-eab3-4bb3-b19d-9d985495c291', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 13, '总结', '{\"page_id\": \"p12\", \"title\": \"课程核心知识点回顾\", \"part\": \"总结\", \"points\": [\"串联建模、UV、材质到渲染的全链路技术闭环\", \"重申规范拓扑布线对模型变形与优化的决定性作用\", \"强调标准化工作流在提升效率与协作中的核心价值\", \"指出通过高频实战练习与案例拆解实现技能内化的必要性\"]}', '{\"text\": \"页面标题：课程核心知识点回顾\\n\\n页面文字：\\n- 串联建模、UV展开、材质贴图到最终渲染的全链路技术闭环逻辑。\\n- 重申规范拓扑布线对模型变形控制与后期优化的决定性作用。\\n- 强调标准化工作流在提升个人效率与团队协作中的核心价值。\\n- 指出通过高频实战练习与深度案例拆解实现技能内化的必要性。\", \"generated_at\": \"2026-03-09T03:39:36.946449\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/6c82e9f2-eab3-4bb3-b19d-9d985495c291_v1.png', 'COMPLETED', '2026-03-09 03:39:27', '2026-03-09 03:50:19', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6d7a7d85-e5a9-4202-bb74-3e1b08cf5f47', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 20, NULL, '{\"page_id\": \"p21\", \"title\": \"评价结语：开启你的工业化建模之旅\", \"layout_id\": \"ending_interactive\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p19\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p21\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928924\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'ending_interactive', '{\"title\": \"开启你的工业化建模之旅\", \"subtitle\": \"评价结语与行动指南。\", \"contact\": \"扫码加入社群 | 获取更多实战素材包\", \"reflection_blocks\": [{\"title\": \"核心思维复盘\", \"items\": [\"拓扑不仅是布线，更是为动画变形预留的“血管”系统。\", \"光影不仅是照明，更是定义虚拟世界情绪与故事的语言。\", \"材质不仅是贴图，更是基于物理属性（PBR）的科学模拟。\"]}, {\"title\": \"下一步行动\", \"items\": [\"立即检查手头项目的布线流向是否支持平滑变形。\", \"尝试在场景中应用IES光源复现真实灯具配光曲线。\", \"整理一份个人常用的材质节点组合库以备复用。\"]}], \"closing\": \"没有完美的模型，只有不断迭代的工作流；让每一次渲染都成为对现实世界的深情致敬。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('6d821e93-681c-4a9c-9c7b-c727d212d766', '6c250523-422a-46f3-a1f1-42e82424897c', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心概念：顶点、边与面的拓扑关系\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"三维坐标轴\", \"线框模型\", \"几何拓扑\", \"学术图解\", \"冷色调\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"顶点(Vertex)\", \"边(Edge)\", \"面(Face)\", \"欧拉公式应用\", \"核心概念：顶点、边与面的拓扑关系的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p02_1\"], \"points\": [\"核心概念：顶点、边与面的拓扑关系的核心概念与背景\", \"核心概念：顶点、边与面的拓扑关系的关键方法与执行要点\", \"核心概念：顶点、边与面的拓扑关系的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p02_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"b\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p02_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286797\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'case_study', '{\"title\": \"典型案例分析\", \"scenario\": \"在低多边形角色建模中，初学者常因忽视拓扑流向导致模型在动画变形时出现非预期的撕裂或褶皱。\", \"challenge\": \"如何设计一个既符合人体肌肉走向又能保证UV展开效率的头部拓扑结构？\", \"points\": [{\"title\": \"顶点(Vertex)定位策略\", \"description\": \"关键特征点（如眼角、嘴角）需精确放置，利用循环边（Loop Edge）控制轮廓，避免在变形关节处产生三角面聚集。\"}, {\"title\": \"边(Edge)布线规则\", \"description\": \"遵循“四边面为主”原则，在肌肉运动区域采用平行于运动方向的环形布线，确保细分曲面后的平滑度。\"}, {\"title\": \"面(Face)与欧拉公式验证\", \"description\": \"通过 V-E+F=2 公式实时校验网格闭合性，确保无孤立项、无自相交，形成合法的流形（Manifold）结构。\"}], \"conclusion\": \"案例启示：优秀的拓扑不仅是几何连接，更是功能性的布线规划，直接决定后续动画变形的质量与渲染效率。\", \"image\": \"https://example.com/case-topology-analysis.jpg\", \"background_image\": \"https://example.com/academic-bg-stone-blue-grid.jpg\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
