INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('712c5255-c67c-4c39-a209-05b6f58f83ff', '7a4f3408-ca73-4a61-998e-174a92497610', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"即时反馈：学习痛点收集\", \"layout_id\": \"feedback_poll\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"最难掌握的环节\", \"最急需的工具\", \"下一步学习方向\", \"即时反馈：学习痛点收集的核心概念与背景\", \"即时反馈：学习痛点收集的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"即时反馈：学习痛点收集的核心概念与背景\", \"即时反馈：学习痛点收集的关键方法与执行要点\", \"即时反馈：学习痛点收集的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267366\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'feedback_poll', '{\"title\": \"即时反馈：学习痛点收集\", \"content\": [\"基于全链路思维导图的闭环认知，聚焦当前环节中最难掌握的拓扑逻辑与布线原则。\", \"请分享您在硬表面处理或有机体塑造中遇到的具体瓶颈，以及最急需的工具支持。\"], \"highlight\": \"识别痛点是优化工作流、提升资产质量的关键第一步。\", \"image\": {\"src\": \"\", \"alt\": \"极简几何网格背景上的互动气泡框，无文字水印\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7230f4b1-bd60-4d5b-ae10-21455fdc6631', '9b5d83ef-2600-4c3b-b852-00607680277d', 1, '导览', '{\"page_id\": \"p02\", \"title\": \"目录：技术演进全景图\", \"part\": \"导览\", \"points\": [\"回顾ChatGPT如何以对话交互打破认知边界，开启大模型元年\", \"解析Claude如何通过安全对齐与超长上下文解决专业场景痛点\", \"阐述Gemini如何利用原生多模态能力重塑Google生态与端云协同\", \"总结三大技术路线的差异化竞争格局并展望通用人工智能未来\"]}', '{\"text\": \"页面标题：目录：技术演进全景图\\n\\n页面文字：\\n为了更全面地展现当前 AI 行业的竞争态势与技术深度，我将你提供的四个核心维度扩展为 20 个具体的技术与行业观察点。\\n-涌现能力的首次具象化：回顾 GPT-3.5 如何通过 RLHF（人类反馈强化学习）让模型具备了惊人的对话逻辑，打破了大众对“聊天机器人”的刻板印象。\\n-Prompt Engineering 的兴起：分析“提示词工程”如何成为连接人类意图与机器算力的桥梁，定义了最初的人机协作模式。\\n-插件与 GPTs 生态：探讨 OpenAI 如何通过 GPTs 尝试构建应用商店，将大模型从单一工具转化为可定制的智能助手平台。\\n-推理模型的范式转移：以 o1 系列模型 为例，解析“思维链”如何让 AI 从单纯的概率预测进化到具备深层逻辑推理能力。\\n-劳动力市场的深层重构：反思 ChatGPT 在翻译、文案、基础代码等领域引发的生产力革命，以及对未来技能需求的结构性改变。\\n-宪法 AI（Constitutional AI）：深入解析 Anthropic 如何通过自监督对齐技术，在减少模型偏见与有害输出方面树立行业标杆。\\n-长上下文的先发优势：回顾 Claude 率先突破 100k/200k context window，如何彻底改变了长文档分析与法务、金融等行业的处理流程。\\n-Computer Use 交互创新：分析 Claude 3.5 Sonnet 如何通过“直接操作电脑”的能力，将 AI 从“对话框”释放到真实的桌面操作系统中。\\n-学术与代码的严谨性：探讨 Claude 在复杂逻辑代码编写与科学论文总结中表现出的低幻觉率，及其在开发者群体中的口碑积累。\\n-Artifacts 的实时协作：解析 Claude 界面如何通过侧边栏实时渲染代码与图表，提升了人机异步协作的效率。\\n-Native Multimodal 的底层逻辑：解释 Gemini 如何从底层开始训练即支持视频、音频和图像，而非通过多个单一模型拼凑。\\n-百万级上下文（1M-2M Token）：分析 Gemini 1.5 Pro 在处理超长视频序列和整库代码重构时的独特技术优势。\\n-Google Workspace 深度整合：探讨 Gemini 如何无缝嵌入 Gmail、Docs 和 Sheets，将 AI 转化为数亿用户的原生生产力套件。\\n-端侧模型（Gemini Nano）的普及：解析 Google 如何利用 Android 生态，在 Pixel 等设备上实现离线、隐私安全的端侧 AI 体验。\\n-Deep Research 的情报能力：评估 Google 利用其搜索搜索底座，如何让 Gemini 在处理长达数百页的复杂课题研究时保持数据实时性。\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/7230f4b1-bd60-4d5b-ae10-21455fdc6631_v1.png', 'FAILED', '2026-03-09 08:13:37', '2026-03-09 09:20:26', NULL, NULL);
