INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('74b121c9-812d-4680-a4b8-2c88aff1d663', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 10, NULL, '{\"title\": \"第一章：重点展开\", \"points\": [\"第一章的核心概念与边界\", \"第一章的典型案例与结果\", \"第一章在本主题中的落地建议\"], \"logical_page_id\": \"p11\", \"has_image\": false, \"keywords\": [\"第一章的核心概念与边界\", \"第一章的典型案例与结果\", \"第一章在本主题中的落地建议\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"第一章的核心概念与边界\", \"第一章的典型案例与结果\", \"第一章在本主题中的落地建议\"], \"promises_open\": [], \"promises_close\": [], \"required_close_promise_ids\": [], \"layout_id\": \"title_content\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227782\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'title_content', '{\"title\": \"第一章：重点展开\", \"content\": [\"核心概念与边界涉及数字底座定位，明确理论到实操转化目标，构建以标准为核心的体系，涵盖关键方法执行要点。\", \"典型复盘显示混淆标准导致失效，统一规范实现闭环。落地建议需结合项目风险灵活调整经验，确保精准对标岗位需求。\"], \"highlight\": \"确认标准化流程是核心驱动力。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('74f62706-2241-4fca-9d3f-682bf3ecf455', '9b5d83ef-2600-4c3b-b852-00607680277d', 15, NULL, '{\"title\": \"第二阶段：重点展开\", \"points\": [\"核心概念聚焦于长上下文窗口技术与安全对齐（Constitutional AI）的深度融合\", \"典型案例展示Claude在百万字文档分析、法律合规审查及医疗诊断辅助中的卓越表现\", \"落地建议强调将AI引入高信任门槛的专业领域，以解决复杂逻辑推理与数据隐私痛点\"]}', '{\"text\": \"页面标题：第二阶段：重点展开\\n\\n页面文字：\\n- 当前阶段核心聚焦于长上下文窗口技术与安全对齐机制的深度融合，彻底解决复杂逻辑推理难题。\\n- Claude在百万字文档分析、法律合规审查及医疗诊断辅助场景中表现卓越，验证了高信任门槛领域的可行性。\\n- 落地建议强调将AI引入专业领域以解决数据隐私痛点，为后续多模态大模型的通用化应用奠定坚实基础。\", \"generated_at\": \"2026-03-09T08:14:15.736975\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/74f62706-2241-4fca-9d3f-682bf3ecf455_v1.png', 'FAILED', '2026-03-09 08:14:05', '2026-03-09 09:20:27', NULL, NULL);
