INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('77a14413-a5c1-4bf5-9031-e8bc61f41a29', '9b5d83ef-2600-4c3b-b852-00607680277d', 13, '总结', '{\"page_id\": \"p12\", \"title\": \"未来展望：迈向AGI的下一步\", \"part\": \"总结\", \"points\": [\"智能体（Agent）将从被动问答进化为具备自主规划与执行能力的主动交互形态\", \"通用大模型将作为底座，与垂直领域专用小模型形成互补共存的生态格局\", \"全球监管框架将加速完善，在伦理安全与创新速度间寻找动态平衡\", \"多模态感知与具身智能结合，推动AI从数字世界向物理世界深度延伸\"]}', '{\"text\": \"未来展望：迈向AGI的下一步\\n\\n页面文字：\\n- 智能体将从被动问答进化为具备自主规划与执行能力的主动交互形态。\\n- 通用大模型将作为底座，与垂直领域专用小模型形成互补共存的生态格局。\\n- 全球监管框架将加速完善，在伦理安全与创新速度间寻找动态平衡。\\n- 多模态感知与具身智能结合，推动AI从数字世界向物理世界深度延伸。\", \"generated_at\": \"2026-03-09T08:14:14.372594\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/77a14413-a5c1-4bf5-9031-e8bc61f41a29_v1.png', 'FAILED', '2026-03-09 08:13:59', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('79b5bf26-34e7-4665-927a-aa212f255d0f', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"核心概念：四边面与三角面的博弈\", \"layout_id\": \"quiz_interaction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"N-gon的局限性\", \"三角面在特定场景的应用\", \"主流引擎兼容性\", \"核心概念：四边面与三角面的博弈的核心概念与背景\", \"核心概念：四边面与三角面的博弈的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"核心概念：四边面与三角面的博弈的核心概念与背景\", \"核心概念：四边面与三角面的博弈的关键方法与执行要点\", \"核心概念：四边面与三角面的博弈的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928349\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'quiz_interaction', '{\"title\": \"核心概念：四边面与三角面的博弈\", \"subtitle\": \"解析不同拓扑形态在引擎中的表现差异。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"四边面优势。\", \"description\": \"提供平滑的细分曲面效果，支持双向流动，是角色建模与动态变形的首选方案。\"}, {\"icon\": \"fa-triangle\", \"text\": \"三角面局限。\", \"description\": \"虽能封闭空间，但会导致细分后产生不可控的折痕，严重破坏表面平滑度。\"}, {\"icon\": \"fa-ban\", \"text\": \"N-gon风险。\", \"description\": \"多边形数量大于四的面片在重拓扑或动画时极易发生扭曲和拉伸错误。\"}, {\"icon\": \"fa-gamepad\", \"text\": \"引擎兼容性。\", \"description\": \"主流游戏引擎（如UE5/Unity）自动将三角面化，若源文件拓扑混乱将导致法线错误。\"}], \"keyTakeaway\": \"坚持四边面主导原则，仅在封闭角落谨慎使用三角面，彻底杜绝 N-gon，是保证模型动态表现稳定的基石。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7c92561d-4fe8-40ca-b82d-b534d4ee2ae0', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 4, NULL, '{\"page_id\": \"p04\", \"title\": \"现状痛点与学习目标对比\", \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"新手常见误区\", \"行业需求差异\", \"现状痛点与学习目标对比的核心概念与背景\", \"现状痛点与学习目标对比的关键方法与执行要点\", \"现状痛点与学习目标对比的应用场景与注意事项\"], \"promises_open\": [{\"promise_id\": \"pr_practice_1\", \"text\": \"具体的操作流程拆解\", \"must_cover\": [\"建模步骤\", \"软件工作流\"], \"target_page_ids\": [\"p26\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"现状痛点与学习目标对比的核心概念与背景\", \"现状痛点与学习目标对比的关键方法与执行要点\", \"现状痛点与学习目标对比的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p05\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227647\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_tri_compare', '{\"title\": \"现状痛点与学习目标对比\", \"left\": {\"header\": \"现状痛点\", \"content\": [\"当前学习普遍存在碎片化问题，脱离实际应用。\"], \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"新手误区：仅重工具操作，忽略底层原理。\", \"description\": \"解释新手误区：仅重工具操作，忽略底层原理在现状痛点维度下的意义。\"}, {\"icon\": \"fa-eye-slash\", \"text\": \"认知偏差：忽视国家战略背景的重要性。\", \"description\": \"解释认知偏差：忽视国家战略背景的重要性在现状痛点维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"需求错位：未对标工业级高精度标准。\", \"description\": \"解释需求错位：未对标工业级高精度标准在现状痛点维度下的意义。\"}, {\"icon\": \"fa-cogs\", \"text\": \"落地困难：缺乏工程化全流程思维。\", \"description\": \"解释落地困难：缺乏工程化全流程思维在现状痛点维度下的意义。\"}]}, \"right\": {\"header\": \"学习目标\", \"content\": [\"目标需指向实战能力转化与国产软件适配。\", \"结论：现状痛点与学习目标对比需要结合目标场景做取舍。\"], \"bullets\": [{\"icon\": \"fa-brain\", \"text\": \"掌握核心算法逻辑基础与三维构建。\", \"description\": \"解释掌握核心算法逻辑基础与三维构建在学习目标维度下的意义。\"}, {\"icon\": \"fa-flag-checkered\", \"text\": \"理解国产软件替代路径与发展趋势。\", \"description\": \"解释理解国产软件替代路径与发展趋势在学习目标维度下的意义。\"}, {\"icon\": \"fa-tasks\", \"text\": \"达成国防级建模精度与交付要求。\", \"description\": \"解释达成国防级建模精度与交付要求在学习目标维度下的意义。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"构建自主创新解决问题能力体系。\", \"description\": \"解释构建自主创新解决问题能力体系在学习目标维度下的意义。\"}]}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7d084297-fe74-4953-9a36-3bd38b8b9965', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 24, NULL, '{\"page_id\": \"p19\", \"title\": \"思政第二课：工匠精神与数字行业伦理\", \"layout_id\": \"edu_qa_case\", \"has_image\": true, \"keywords\": [\"天平图标\", \"版权保护符号\", \"团队协作剪影\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"知识产权尊重\", \"原创精神培养\", \"数据安全与合规\", \"思政第二课的核心概念与背景\", \"思政第二课的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"思政第二课的核心概念与背景\", \"思政第二课的关键方法与执行要点\", \"思政第二课的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p25\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T12:17:13.187735\"}', NULL, 'FAILED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_qa_case', '{\"title\": \"数字创作伦理准则\", \"question\": \"项目使用素材如何规避侵权风险？\", \"answer\": \"核对授权许可，商用购正版，练习注出处。\", \"analysis\": [{\"title\": \"版权与原创\", \"content\": \"尊重知识产权，坚持原创精神，禁止抄袭挪用。\"}, {\"title\": \"安全与执行\", \"content\": \"落实数据安全合规，严格执行行业伦理执行要点。\"}], \"conclusion\": \"守正创新，做有温度的数字工匠。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"qa_session\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7dbbf52b-3b6e-4752-8e6c-e2c44c0702af', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 3, '基础准备', '{\"page_id\": \"p03\", \"title\": \"主流建模软件对比分析\", \"part\": \"基础准备\", \"points\": [\"Blender：全功能开源免费，社区插件丰富，适合独立创作者与初学者入门\", \"Maya/3ds Max：行业标准软件，在影视特效与大型游戏开发中占据主导地位\", \"C4D：以操作流畅著称，是广告设计与动态图形（Motion Graphics）的首选工具\", \"决策建议：根据职业目标选择软件，初学者可从 Blender 切入降低学习成本\"]}', '{\"text\": \"页面标题：主流建模软件对比分析\\n\\n页面文字：\\n- Blender作为全功能开源软件，凭借丰富社区插件成为独立创作者与初学者的首选入门工具。\\n- Maya与3ds Max占据影视特效及大型游戏开发主导地位，是行业标准的专业级解决方案。\\n- C4D以操作流畅著称，在广告设计与动态图形领域拥有不可替代的广泛应用场景。\\n- 建议根据职业目标选择软件，初学者可从Blender切入以有效降低学习成本与试错风险。\", \"generated_at\": \"2026-03-09T03:39:37.774078\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/7dbbf52b-3b6e-4752-8e6c-e2c44c0702af_v1.png', 'COMPLETED', '2026-03-09 03:39:12', '2026-03-09 03:40:39', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7e8c5fbe-7188-4f10-8701-dd26a89d04fc', 'b494fc12-8d48-4b4c-8717-9faa745d5f79', 16, NULL, '{\"page_id\": \"p17\", \"title\": \"即时反馈：你选择哪种烘焙方案？\", \"layout_id\": \"feedback_poll\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"方案A优缺点\", \"方案B优缺点\", \"决策依据\", \"即时反馈：你选择哪种烘焙方案？的核心概念与背景\", \"即时反馈：你选择哪种烘焙方案？的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"即时反馈：你选择哪种烘焙方案？的核心概念与背景\", \"即时反馈：你选择哪种烘焙方案？的关键方法与执行要点\", \"即时反馈：你选择哪种烘焙方案？的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 02:23:20', '2026-03-08 02:23:20', 'feedback_poll', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7ec30dcb-ca44-4666-a8d6-77d7ea989bb8', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 19, NULL, '{\"page_id\": \"p20\", \"title\": \"学习资源推荐与进阶路径\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p18\"], \"must_cover\": [\"官方文档链接\", \"优质教程网站\", \"插件工具包\", \"社区交流渠道\", \"学习资源推荐与进阶路径的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"学习资源推荐与进阶路径的核心概念与背景\", \"学习资源推荐与进阶路径的关键方法与执行要点\", \"学习资源推荐与进阶路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p20\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928891\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'group_collab', '{\"title\": \"学习资源推荐与进阶路径\", \"subtitle\": \"构建你的工业化建模知识体系。\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"官方文档与规范。\", \"description\": \"深入阅读Autodesk及Blender官方文档，掌握PBR标准与拓扑规范，确保资产符合工业交付要求。\"}, {\"icon\": \"fa-video\", \"text\": \"优质教程网站。\", \"description\": \"推荐CGSociety与ArtStation精选课程，重点学习角色变形控制与复杂场景的光影叙事技巧。\"}, {\"icon\": \"fa-plug\", \"text\": \"插件工具包。\", \"description\": \"集成TopoGun与SpeedTree等高效插件，提升布线效率与植被生成速度，缩短项目周期。\"}, {\"icon\": \"fa-users\", \"text\": \"社区交流渠道。\", \"description\": \"加入专业3D论坛与Discord群组，参与技术研讨，获取最新渲染器优化方案与避坑指南。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"进阶路径建议。\", \"description\": \"从基础拓扑入手，逐步掌握材质节点逻辑，最终实现从模型构建到光影渲染的全流程掌控。\"}], \"keyTakeaway\": \"系统化整合官方规范、工具链与社区资源，是突破个人瓶颈、迈向工业化生产的关键。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
