INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('7f070f44-13ff-4448-9d03-692e14ca9c89', '9b5d83ef-2600-4c3b-b852-00607680277d', 10, '应用价值', '{\"page_id\": \"p09\", \"title\": \"行业影响：重塑内容生产与工作流\", \"part\": \"应用价值\", \"points\": [\"生成式AI实现文案、代码与视觉素材的自动化批量生产，显著提升创意产出效率\", \"个性化教育辅导与智能客服系统成为行业标准配置，推动服务体验从通用化向定制化转型\", \"企业级应用加速从概念验证走向规模化落地，深度重构研发、营销与运营核心工作流\"]}', '{\"text\": \"页面标题：行业影响：重塑内容生产与工作流\\n\\n页面文字：\\n- 生成式AI实现文案、代码与视觉素材自动化批量生产，显著提升创意产出效率。\\n- 个性化教育辅导与智能客服系统成为行业标准配置，推动服务体验从通用化向定制化转型。\\n- 企业级应用加速从概念验证走向规模化落地，深度重构研发、营销与运营核心工作流。\", \"generated_at\": \"2026-03-09T08:14:14.326505\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/7f070f44-13ff-4448-9d03-692e14ca9c89_v1.png', 'FAILED', '2026-03-09 08:13:54', '2026-03-09 09:20:26', NULL, NULL);
