INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8bf92cb2-ad22-4ed9-bb37-452fae211f1b', '2210a36d-b61a-453a-83ee-86edc9925e6a', 11, NULL, '{\"page_id\": \"p12\", \"title\": \"高级案例：硬表面机械零件\", \"layout_id\": \"case_study\", \"has_image\": true, \"keywords\": [\"金属质感模型特写\", \"高光反射细节\", \"工业风格渲染图\", \"阴影层次展示\"], \"depends_on\": [\"p10\"], \"must_cover\": [\"布尔运算清理\", \"倒角半径统一\", \"PBR 材质贴图\", \"高级案例：硬表面机械零件的核心概念与背景\", \"高级案例：硬表面机械零件的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_advanced\"], \"points\": [\"高级案例：硬表面机械零件的核心概念与背景\", \"高级案例：硬表面机械零件的关键方法与执行要点\", \"高级案例：硬表面机械零件的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_advanced\"], \"logical_page_id\": \"p12\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p08_advanced\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647727\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'case_study', '{\"title\": \"典型案例分析\", \"scenario\": \"工业级硬表面机械零件高精度建模\", \"challenge\": \"布尔运算后边缘锐利度不足及材质反射失真\", \"points\": [{\"title\": \"布尔清理\", \"description\": \"保留有效几何边，移除多余顶点。\"}, {\"title\": \"倒角统一\", \"description\": \"控制半径一致，确保高光连贯。\"}, {\"title\": \"PBR 贴图\", \"description\": \"金属粗糙度与法线细节结合。\"}], \"conclusion\": \"细节精度与物理参数决定最终渲染的真实感\", \"image\": {\"src\": \"\", \"alt\": \"机械零件金属质感渲染特写\", \"position\": \"right\", \"width\": \"35%\"}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8cb53a7a-d418-4601-8bd4-0b23c2cef9c7', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 13, NULL, '{\"title\": \"爆发期：重点展开\", \"points\": [\"核心概念：以深度学习为基石，依托海量数据与 GPU 算力实现从感知智能到生成智能的跨越\", \"典型案例：2012年AlexNet确立CNN统治地位，随后Transformer架构引爆大语言模型（LLM）革命\", \"关键结果：AI在图像识别、自然语言处理及科学发现领域取得突破性进展，推动产业智能化升级\", \"落地建议：企业应聚焦垂直场景的数据清洗与标注，构建私有化大模型以平衡通用能力与业务安全\"]}', '{\"text\": \"页面标题：爆发期：重点展开\\n\\n页面文字：\\n- 以深度学习为基石，依托海量数据与GPU算力实现从感知智能到生成智能的历史性跨越。\\n- 2012年AlexNet确立CNN统治地位，随后Transformer架构引爆大语言模型革命并重塑行业格局。\\n- AI在图像识别、自然语言处理及科学发现领域取得突破，推动产业智能化升级进入快车道。\\n- 企业应聚焦垂直场景的数据清洗与标注，构建私有化大模型以平衡通用能力与业务安全需求。\", \"generated_at\": \"2026-03-09T08:54:47.550872\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:38', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8d63c234-69ee-45f3-b153-1f64c583d88e', '7a4f3408-ca73-4a61-998e-174a92497610', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"课前探究：你眼中的3D世界？\", \"layout_id\": \"warmup_inquiry\", \"has_image\": true, \"keywords\": [\"沉浸式摄影风格\", \"虚实结合场景\", \"工业质感物体\", \"思考气泡图标\", \"低饱和度背景\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"行业应用场景列举\", \"常见误区提问\", \"思维引导线\", \"课前探究：你眼中的3D世界？的核心概念与背景\", \"课前探究：你眼中的3D世界？的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课前探究：你眼中的3D世界？的核心概念与背景\", \"课前探究：你眼中的3D世界？的关键方法与执行要点\", \"课前探究：你眼中的3D世界？的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266547\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'warmup_inquiry', '{\"question\": \"你眼中的3D世界是纯粹的虚拟构建，还是虚实共生的工业场景？\", \"thinkTime\": 30, \"hints\": [\"观察现实中的工业设计产品与数字渲染图的差异\", \"思考沉浸式摄影如何模糊真实与虚拟的边界\"], \"background_image\": \"https://example.com/assets/low_saturation_3d_background.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8df6b0ae-6624-4628-aaa3-7da7a916f825', '766dd313-1e7e-43f8-b4e9-3ca4b9e71dd6', 19, NULL, '{\"title\": \"总结与答疑\", \"points\": [\"核心结论：建模核心机制解析的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"layout_id\": \"edu_data_board\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p20\", \"depends_on\": [\"p19\"], \"must_cover\": [\"核心结论：建模核心机制解析的关键认知与边界\", \"行动建议：下一步如何落地与评估效果\", \"开放答疑：常见问题与延伸讨论方向\"], \"promises_open\": [], \"required_close_promise_ids\": [\"pr_p18_1_f9abd56f\", \"pr_p02_1\", \"pr_p03_1\", \"pr_p05_1\", \"pr_p08_1\", \"pr_p11_1\", \"pr_p14_1\"], \"promises_close\": [\"pr_p18_1_f9abd56f\", \"pr_p02_1\", \"pr_p03_1\", \"pr_p05_1\", \"pr_p08_1\", \"pr_p11_1\", \"pr_p14_1\"]}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-06 09:45:17', '2026-03-06 09:45:17', 'edu_data_board', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('8f033926-8f47-4419-884d-c7de3113282b', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 2, '第一阶段', '{\"page_id\": \"p03\", \"title\": \"萌芽期：图灵、达特茅斯会议与早期构想\", \"part\": \"第一阶段\", \"points\": [\"1950年图灵发表《计算机器与智能》，提出“图灵测试”奠定机器思维哲学基石\", \"1956年达特茅斯会议汇聚学界精英，正式确立“人工智能”学科名称并开启探索纪元\", \"早期突破：逻辑理论家（Logic Theorist）等程序诞生，验证了机器模拟人类推理的可行性\", \"技术瓶颈：受限于当时硬件算力与存储能力，复杂模型无法训练，为后续寒冬埋下伏笔\"]}', '{\"text\": \"页面标题：萌芽期：图灵、达特茅斯会议与早期构想\\n\\n页面文字：\\n- 1950年图灵发表著作提出“图灵测试”，为机器思维奠定了坚实的哲学理论基础。\\n- 1956年达特茅斯会议汇聚学界精英，正式确立学科名称并开启长达数十年的探索纪元。\\n- 早期逻辑理论家程序诞生验证了机器模拟人类推理的可行性，但受限于算力无法训练复杂模型。\\n- 这一时期的硬件瓶颈为后续寒冬埋下伏笔，也促使研究者不断反思技术路径与突破方向。\", \"generated_at\": \"2026-03-09T08:54:47.422430\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:22', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('918aa535-bc94-4b9e-bb54-cc2ec79f67c3', 'dbda8f0a-50a4-41ad-beaa-ab13ba9d20a1', 1, NULL, '{\"title\": \"核心内容\", \"points\": [\"技术原理\"]}', '{\"text\": \"页面标题：核心内容\\n页面文字：\\n- 新核心内容描述\", \"generated_at\": \"2026-03-08T15:04:43.787193\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-08 07:04:44', '2026-03-08 15:04:44', NULL, NULL);
