INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('97df8b4b-2ad5-424a-b7c2-d362bce98526', '9b5d83ef-2600-4c3b-b852-00607680277d', 14, 'ChatGPT篇', '{\"title\": \"第一阶段：重点展开\", \"points\": [\"核心概念界定为‘对话式大模型觉醒期’，以RLHF技术实现人类价值观对齐与通用对话能力突破\", \"典型案例包括2022年11月发布后全球用户数破亿，以及代码解释器插件在编程辅助场景的规模化落地\", \"落地建议聚焦于利用成熟API构建智能客服与内容生成工作流，同时建立针对幻觉风险的校验机制\"], \"part\": \"ChatGPT篇\"}', '{\"text\": \"第一阶段：重点展开\\n\\n页面文字：\\n- 核心概念界定为对话式大模型觉醒期，以RLHF技术实现人类价值观对齐与通用对话能力突破。\\n- 典型案例包括2022年11月发布后全球用户数破亿，以及代码解释器插件在编程辅助场景的规模化落地。\\n- 落地建议聚焦于利用成熟API构建智能客服与内容生成工作流，同时建立针对幻觉风险的校验机制。\", \"generated_at\": \"2026-03-09T08:14:14.372596\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/97df8b4b-2ad5-424a-b7c2-d362bce98526_v1.png', 'FAILED', '2026-03-09 08:14:00', '2026-03-09 09:20:27', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('989ea7b5-a621-4726-a665-cf690fb802ab', '2210a36d-b61a-453a-83ee-86edc9925e6a', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"拓扑结构与几何算法推导\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p04\"], \"must_cover\": [\"Euler Characteristic 公式应用\", \"布线方向性对渲染的影响\", \"拓扑结构与几何算法推导的核心概念与背景\", \"拓扑结构与几何算法推导的关键方法与执行要点\", \"拓扑结构与几何算法推导的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p04_topology\"], \"points\": [\"拓扑结构与几何算法推导的核心概念与背景\", \"拓扑结构与几何算法推导的关键方法与执行要点\", \"拓扑结构与几何算法推导的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p04_topology\"], \"logical_page_id\": \"p05\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p04_topology\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647605\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'theory_explanation', '{\"title\": \"拓扑结构与几何算法推导\", \"theory\": [\"基于欧拉示性数公式验证网格整体完整性，\", \"区分流形面片与非流形区域的拓扑特征。\", \"布线方向直接影响光线追踪计算与阴影分布。\"], \"formulas\": [{\"latex\": \"$\\\\chi = V - E + F = 2$\", \"explanation\": \"球体类网格的拓扑不变量常数。\"}], \"references\": [\"计算机图形学教材 P45\", \"Polygon Modeling Standards 2024\"], \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('98bb4400-b51a-416d-9828-e2af36699714', '7a4f3408-ca73-4a61-998e-174a92497610', 18, NULL, '{\"page_id\": \"p19\", \"title\": \"结语：开启你的3D创作之旅\", \"layout_id\": \"ending_interactive\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p17\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"a\", \"logical_page_id\": \"p19\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267670\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 09:38:40', 'ending_interactive', '{\"title\": \"结语：开启你的3D创作之旅\", \"subtitle\": \"从顶点到渲染，每一步都算数。\", \"contact\": \"扫码加入行业交流群 | 获取最新拓扑模板库\", \"reflection_blocks\": [{\"title\": \"反思维度：从痛点到突破\", \"items\": [\"回顾硬表面处理中的布线瓶颈，思考今日所学如何优化工作流\", \"将工匠精神的数字化表达转化为具体的参数化操作习惯\"]}, {\"title\": \"反思维度：资源与路径\", \"items\": [\"确认已收藏官方文档与核心教程，建立个人技术知识库\", \"规划下一阶段任务：选择一个有机体模型进行全流程实战\"]}], \"closing\": \"工匠精神不是重复劳动，而是对每一个顶点、每一条边线的极致负责；现在，请拿起工具，开启你的第一个完美闭环。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('996222fe-0432-4c51-865d-eb0887f26967', '6c250523-422a-46f3-a1f1-42e82424897c', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"课程目录与学习路径\", \"layout_id\": \"toc_academic\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [{\"promise_id\": \"pr_p02_1\", \"text\": \"详细拆解多边形建模的核心逻辑与拓扑原则\", \"must_cover\": [\"拓扑结构\", \"布线规则\", \"法线方向\"], \"target_page_ids\": [\"p21\"], \"is_hard\": true}, {\"promise_id\": \"pr_p02_2\", \"text\": \"展示从草图到成品的完整工作流\", \"must_cover\": [\"建模步骤\", \"渲染设置\", \"输出规范\"], \"target_page_ids\": [\"p21\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286711\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'toc_academic', '{\"title\": \"学习路径与能力进阶\", \"items\": [{\"index\": 1, \"text\": \"阶段一：理论奠基（认知层）- 理解欧拉角、法线与网格流。\"}, {\"index\": 2, \"text\": \"阶段二：工具掌握（应用层）- 熟练运用布尔运算与细分曲面。\"}, {\"index\": 3, \"text\": \"阶段三：管线整合（分析层）- 完成从建模到引擎导入的完整工作流。\"}, {\"index\": 4, \"text\": \"阶段四：风格化突破（创造层）- 掌握写实与卡通风格的差异化表现。\"}], \"background_image\": null, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9abf54c4-55ee-44b7-ab36-7e874122cb9e', '9b5d83ef-2600-4c3b-b852-00607680277d', 11, '风险探讨', '{\"page_id\": \"p10\", \"title\": \"挑战与隐忧：伦理、偏见与版权\", \"part\": \"风险探讨\", \"points\": [\"模型幻觉导致事实性错误频发，严重制约其在医疗、法律等高风险场景的落地应用\", \"训练数据版权归属模糊引发全球诉讼潮，迫使企业重构数据合规与授权机制\", \"生成式内容易被用于制造深度伪造（Deepfake），对新闻真实性与社会信任体系构成严峻挑战\", \"算法隐含的性别、种族等社会偏见若未被有效修正，将加剧现实世界的不平等现象\"]}', '{\"text\": \"页面标题：挑战与隐忧：伦理、偏见与版权\\n\\n页面文字：\\n- 模型幻觉导致事实性错误频发，严重制约其在医疗、法律等高风险场景的落地应用。\\n- 训练数据版权归属模糊引发全球诉讼潮，迫使企业重构数据合规与授权机制。\\n- 生成式内容易被用于制造深度伪造，对新闻真实性与社会信任体系构成严峻挑战。\\n- 算法隐含的社会偏见若未被有效修正，将加剧现实世界的不平等现象。\", \"generated_at\": \"2026-03-09T08:14:14.326507\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/9abf54c4-55ee-44b7-ab36-7e874122cb9e_v1.png', 'FAILED', '2026-03-09 08:13:55', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9aca30f4-e1fd-4464-84be-92d76d1a036f', '2210a36d-b61a-453a-83ee-86edc9925e6a', 14, NULL, '{\"page_id\": \"p15\", \"title\": \"硬件配置与运行环境对比\", \"layout_id\": \"comparison_table\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p12\"], \"must_cover\": [\"CPU 单核性能需求\", \"显卡显存容量建议\", \"内存扩展方案\", \"硬件配置与运行环境对比的核心概念与背景\", \"硬件配置与运行环境对比的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"硬件配置与运行环境对比的核心概念与背景\", \"硬件配置与运行环境对比的关键方法与执行要点\", \"硬件配置与运行环境对比的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p15\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647770\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'comparison_table', '{\"title\": \"对比分析\", \"subtitle\": \"工作流硬件性能需求评估。\", \"items\": [{\"name\": \"CPU 单核性能\", \"description\": \"建模操作主要依赖单线程计算速度，影响交互流畅度。\", \"features\": [\"高频主频优先\", \"低延迟响应机制\", \"复杂视图实时计算\"]}, {\"name\": \"GPU 显存容量\", \"description\": \"渲染预览与光照计算需要大量显存支持纹理加载。\", \"features\": [\"大纹理无缝加载\", \"光线追踪硬件加速\", \"视口平滑渲染\"]}, {\"name\": \"内存扩展方案\", \"description\": \"存储场景数据以防程序崩溃，确保多任务并行稳定。\", \"features\": [\"高容量随机存取\", \"分层缓存管理机制\", \"数据交换安全性\"]}], \"conclusion\": \"高单核 CPU 提升操作流畅度，大显存 GPU 保障纹理分辨率，大容量内存避免场景崩溃。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9af70f9e-bd05-4917-a270-e43205df4d00', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 4, '理论基石', '{\"page_id\": \"p04\", \"title\": \"核心概念：多边形与拓扑结构\", \"part\": \"理论基石\", \"points\": [\"掌握顶点、边、面三大基础元素的连接逻辑与层级关系\", \"理解循环布线如何决定模型变形流畅度与渲染光影效果\", \"区分低模（游戏）与高模（影视）在拓扑密度上的核心差异\", \"识别三角面、四边面与N-gon在不同软件中的处理规范\"]}', '{\"text\": \"页面标题：核心概念：多边形与拓扑结构\\n\\n页面文字：\\n- 需深入掌握顶点、边、面三大基础元素的连接逻辑及其层级关系以构建正确模型骨架。\\n- 循环布线直接决定模型变形的流畅度以及渲染光影的最终呈现效果，是拓扑的核心价值。\\n- 必须区分低模与高模在拓扑密度上的差异，前者服务于游戏实时渲染，后者用于影视细节。\\n- 应严格识别三角面、四边面与N-gon在不同软件中的处理规范，避免后续流程出现技术故障。\", \"generated_at\": \"2026-03-09T03:39:37.774093\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/9af70f9e-bd05-4917-a270-e43205df4d00_v1.png', 'COMPLETED', '2026-03-09 03:39:13', '2026-03-09 03:42:54', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9b250f8e-f772-444f-aabf-6f5df821f434', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"什么是冒泡排序？\", \"layout_id\": \"field_observation\", \"has_image\": true, \"keywords\": [\"带比例尺的数据网格\", \"微观粒子运动\", \"专业标注红圈\", \"古籍黄背景\", \"高精度测绘图\"], \"depends_on\": [\"p03\"], \"must_cover\": [\"基本定义\", \"核心操作单元（相邻交换）\", \"什么是冒泡排序？的核心概念与背景\", \"什么是冒泡排序？的关键方法与执行要点\", \"什么是冒泡排序？的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p03_1\"], \"points\": [\"什么是冒泡排序？的核心概念与背景\", \"什么是冒泡排序？的关键方法与执行要点\", \"什么是冒泡排序？的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p03_1\"], \"layout_archetype\": \"case_visual\", \"layout_variant\": \"a\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.831944\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'field_observation', '{\"title\": \"算法现场：数据流动的微观观测\", \"image_src\": \"https://example.com/images/bubble-sort-field-observation.jpg\", \"image_alt\": \"一张带有精密比例尺和经纬度网格的古籍黄背景图，展示微观粒子（数据元素）在无序状态下的运动轨迹，红圈标注出正在进行交换的两个相邻粒子，整体呈现高精度测绘图的质感。\", \"caption\": \"图 2.1 冒泡排序的现场观测视角：数据元素如同深海气泡，通过两两比较与交换，在物理类比中逐步上浮至有序位置。\", \"background_image\": \"https://example.com/images/darkwood-overlay-bg.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"case_visual\"}');
