INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9e615d5b-5e81-4518-9fbc-743e751968f4', '8f10b0ec-ba8a-41c7-9730-10360d6d560d', 10, NULL, '{\"title\": \"项目实战步骤推进图：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p11\", \"depends_on\": [\"p10\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [{\"promise_id\": \"pr_p11_1_45a7b205\", \"text\": \"项目实战步骤推进图：案例复盘的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"b\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T07:30:15.651593\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 07:23:27', '2026-03-08 01:01:15', 'edu_tri_compare', '{\"title\": \"项目实战步骤推进图：案例复盘\", \"badge\": \"实战验证\", \"columns\": [{\"title\": \"问题与场景\", \"points\": [\"初始素材匮乏难找\", \"需求理解存在偏差\", \"交付时间周期紧迫\"]}, {\"title\": \"方案与执行\", \"points\": [\"建立标准素材库\", \"实施多级评审制\", \"动态调整优先级\"]}, {\"title\": \"结果与启示\", \"points\": [\"整体效率提升显著\", \"返工率降至最低\", \"沉淀可复用 SOP\"]}], \"left\": {\"header\": \"维度一\", \"content\": [\"项目实战步骤推进图：案例复盘在维度一下的核心结论与适用条件。\"], \"bullets\": []}, \"right\": {\"header\": \"维度二\", \"content\": [\"项目实战步骤推进图：案例复盘在维度二下的核心结论与适用条件。\"], \"bullets\": []}, \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9f557706-90bd-46cf-9430-2c5dfb084360', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 9, '反思', '{\"page_id\": \"p09\", \"title\": \"挑战与伦理：算法偏见与未来风险\", \"part\": \"反思\", \"points\": [\"数据训练偏差导致招聘、信贷等场景出现系统性算法歧视\", \"Deepfake技术引发身份伪造危机，严重冲击社会信任基石\", \"自动化替代效应加剧就业结构性矛盾，需关注社会公平转型\"]}', '{\"text\": \"页面标题：挑战与伦理：算法偏见与未来风险\\n\\n页面文字：\\n- 数据训练偏差导致招聘、信贷等场景出现系统性算法歧视，需警惕技术不公。\\n- Deepfake技术引发身份伪造危机，严重冲击社会信任基石并带来法律挑战。\\n- 自动化替代效应加剧就业结构性矛盾，必须关注社会公平转型的紧迫性。\\n这些挑战警示我们，在追求技术突破的同时，更需构建负责任的AI治理框架。\", \"generated_at\": \"2026-03-09T08:54:48.435834\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:32', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('9f90a38f-ccea-42ec-a07e-37cc9559f49d', '14c0f24c-10e7-4309-a927-d9db1066897c', 4, NULL, '{\"page_id\": \"p05\", \"title\": \"基础图元：多面体的生成逻辑\", \"layout_id\": \"gallery_professional\", \"has_image\": true, \"keywords\": [\"立方体线框\", \"球体网格\", \"圆柱体截面\", \"高清图库\", \"工业级质感\"], \"depends_on\": [\"p04\"], \"must_cover\": [\"基本几何体参数\", \"细分原理\", \"图元组合\", \"基础图元：多面体的生成逻辑的核心概念与背景\", \"基础图元：多面体的生成逻辑的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p05_1\", \"text\": \"后续将深入讲解复杂模型的拓扑优化方法\", \"must_cover\": [\"布线技巧\", \"优化策略\"], \"target_page_ids\": [\"p17\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"基础图元：多面体的生成逻辑的核心概念与背景\", \"基础图元：多面体的生成逻辑的关键方法与执行要点\", \"基础图元：多面体的生成逻辑的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p05\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773775\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'gallery_professional', '{\"title\": \"基础图元：多面体的生成逻辑\", \"subtitle\": \"从参数化定义到网格细分的演化。\", \"items\": [{\"image_src\": \"https://images.unsplash.com/photo-1633596683562-4a47eb6f8d7b?auto=format&fit=crop&q=80&w=800\", \"title\": \"立方体线框架构\", \"description\": \"展示基于最小顶点数构成的最简多面体，体现参数化调整对长宽高的精确控制能力。\", \"tags\": [\"立方体\", \"线框\", \"参数化\"]}, {\"image_src\": \"https://images.unsplash.com/photo-1618005182384-a83a8bd57fbe?auto=format&fit=crop&q=80&w=800\", \"title\": \"球体网格细分\", \"description\": \"演示低模向高模过渡的细分原理，观察极点分布对曲面平滑度的影响及拓扑优化策略。\", \"tags\": [\"球体\", \"细分\", \"网格\"]}, {\"image_src\": \"https://images.unsplash.com/photo-1633596683562-4a47eb6f8d7b?auto=format&fit=crop&q=80&w=800\", \"title\": \"圆柱体截面分析\", \"description\": \"解析旋转体的生成逻辑，通过截面变化理解边数设置对圆滑度与面数的平衡取舍。\", \"tags\": [\"圆柱体\", \"截面\", \"旋转\"]}], \"layout\": \"grid\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('a12ca233-2635-4244-8bce-46ee48a37e78', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 3, '第一阶段', '{\"page_id\": \"p04\", \"title\": \"第一次浪潮：专家系统的崛起与瓶颈\", \"part\": \"第一阶段\", \"points\": [\"MYCIN等系统成功应用于医疗诊断，确立了知识工程的核心地位\", \"基于规则的系统在地质勘探、化学分析等领域实现早期商业化落地\", \"缺乏通用推理能力导致系统难以迁移，维护成本随规则膨胀而激增\", \"僵化的逻辑架构无法应对复杂场景，直接引发了第二次AI寒冬\"]}', '{\"text\": \"页面标题：第一次浪潮：专家系统的崛起与瓶颈\\n\\n页面文字：\\n- MYCIN等系统成功应用于医疗诊断，确立了知识工程在专业领域的核心地位。\\n- 基于规则的系统在地质勘探、化学分析等领域实现早期商业化落地应用。\\n- 缺乏通用推理能力导致系统难以迁移，维护成本随规则膨胀而激增。\\n- 僵化的逻辑架构无法应对复杂场景，直接引发了第二次AI寒冬的到来。\", \"generated_at\": \"2026-03-09T08:54:47.141682\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:23', '2026-03-09 08:54:49', NULL, NULL);
