INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b0f75d68-539a-407f-8486-ed213f15c126', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 5, NULL, '{\"page_id\": \"p06\", \"title\": \"案例复盘：一次完整的冒泡过程\", \"layout_id\": \"gallery_professional\", \"has_image\": true, \"keywords\": [\"多帧连续动作拼接\", \"数据变化快照集\", \"高清微距质感\", \"学术档案页\", \"黑白灰调\"], \"depends_on\": [\"p05\"], \"must_cover\": [\"初始状态\", \"中间交换\", \"最终有序\", \"案例复盘：一次完整的冒泡过程的核心概念与背景\", \"案例复盘：一次完整的冒泡过程的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_1\"], \"points\": [\"案例复盘：一次完整的冒泡过程的核心概念与背景\", \"案例复盘：一次完整的冒泡过程的关键方法与执行要点\", \"案例复盘：一次完整的冒泡过程的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p06\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832031\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'gallery_professional', '{\"title\": \"案例复盘：一次完整的冒泡过程\", \"subtitle\": \"从混乱到秩序的五帧定格。\", \"items\": [{\"image_src\": \"https://example.com/images/sorting-frame-initial.jpg\", \"title\": \"初始状态：无序集合\", \"description\": \"数据序列 [5, 3, 8, 4, 2] 处于完全随机分布状态，无任何局部有序特征，背景呈现深木棕色调，象征待处理的混沌数据流。\", \"tags\": [\"初始态\", \"高熵值\"]}, {\"image_src\": \"https://example.com/images/sorting-frame-swap1.jpg\", \"title\": \"中间交换：第一轮碰撞\", \"description\": \"执行第一遍遍历，5 与 3 交换，随后 5 与 8 不交换，8 与 4 交换，最大元素 8 开始向右侧边缘移动，黑白灰调凸显动作瞬间。\", \"tags\": [\"交换动作\", \"局部有序\"]}, {\"image_src\": \"https://example.com/images/sorting-frame-swap2.jpg\", \"title\": \"持续上浮：极值归位\", \"description\": \"经过多轮穿梭，数值最大的元素 8 已稳固停留在数组末尾，剩余子序列继续通过两两比较进行微调，画面呈现动态模糊感。\", \"tags\": [\"极值定位\", \"递归缩减\"]}, {\"image_src\": \"https://example.com/images/sorting-frame-final.jpg\", \"title\": \"最终有序：完美归档\", \"description\": \"所有元素完成排序变为 [2, 3, 4, 5, 8]，序列呈现完美的线性上升阶梯状，象征数据流动的智慧终局与系统的高效运转。\", \"tags\": [\"最终态\", \"低熵值\"]}], \"layout\": \"grid\", \"background_image\": \"https://example.com/images/academic-archive-bg.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
