INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b67d16b2-700e-4b5b-9910-3e2ea91208af', '7a4f3408-ca73-4a61-998e-174a92497610', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"第三章：UV展开与材质纹理映射\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"UV空间概念\", \"拉伸与重叠检测\", \"PBR工作流简介\", \"第三章：UV展开与材质纹理映射的核心概念与背景\", \"第三章：UV展开与材质纹理映射的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"第三章：UV展开与材质纹理映射的核心概念与背景\", \"第三章：UV展开与材质纹理映射的关键方法与执行要点\", \"第三章：UV展开与材质纹理映射的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p11\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266868\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:25', 'group_collab', '{\"title\": \"第三章：UV展开与材质纹理映射\", \"subtitle\": \"连接三维模型与二维纹理的数字化桥梁。\", \"bullets\": [{\"icon\": \"fa-map-o\", \"text\": \"UV空间基础概念解析。\", \"description\": \"理解UV坐标系如何将三维曲面坐标映射至二维平面，确立纹理像素密度（Texel Density）的基准单位。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"拉伸与重叠检测技术。\", \"description\": \"利用热力图可视化检测UV拉伸异常区域，消除因重叠导致的纹理错位与渲染伪影。\"}, {\"icon\": \"fa-paint-brush\", \"text\": \"PBR工作流简介。\", \"description\": \"整合漫反射、法线、粗糙度等通道，构建符合物理规律的材质表现体系，实现工业级真实感渲染。\"}, {\"icon\": \"fa-project-diagram\", \"text\": \"关键方法与执行要点。\", \"description\": \"掌握智能展开与手动调整相结合的混合策略，确保UV岛布局紧凑且边缘切缝隐蔽。\"}], \"keyTakeaway\": \"UV展开是决定材质表现上限的核心环节，科学的布局策略能大幅提升纹理利用率并避免渲染瑕疵。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b7181bb3-f81e-4422-8b39-1cc90d635b33', '6c250523-422a-46f3-a1f1-42e82424897c', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"流程图解：参数化建模的标准步骤\", \"layout_id\": \"diagram_illustration\", \"has_image\": true, \"keywords\": [\"流程图\", \"决策树\", \"数据流向\", \"层级结构\", \"逻辑连接\"], \"depends_on\": [\"p11\"], \"must_cover\": [\"草图绘制\", \"拉伸/旋转\", \"布尔运算\", \"倒角处理\", \"流程图解：参数化建模的标准步骤的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"流程图解：参数化建模的标准步骤的核心概念与背景\", \"流程图解：参数化建模的标准步骤的关键方法与执行要点\", \"流程图解：参数化建模的标准步骤的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287017\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'diagram_illustration', '{\"title\": \"参数化建模标准步骤图解\", \"subtitle\": \"从草图到成品的数据驱动流程。\", \"explanations\": [{\"label\": \"草图绘制 (Sketching)\", \"description\": \"在二维平面定义关键轮廓线与约束条件，作为三维生成的基准框架；需确保闭合性与尺寸标注完整，为后续拉伸/旋转提供准确拓扑引导。\"}, {\"label\": \"拉伸/旋转 (Extrude/Rotate)\", \"description\": \"基于草图轮廓沿指定轴生成三维体积，是参数化建模最基础的几何转换操作；支持实时预览与参数联动，允许快速调整截面形状与延伸长度。\"}, {\"label\": \"布尔运算 (Boolean Operations)\", \"description\": \"通过并集、差集或交集合并/切割多个实体，用于创建复杂孔洞或组合结构；需注意网格流连续性，避免产生非流形边或自相交面影响后续细分。\"}, {\"label\": \"倒角处理 (Bevel/Fillet)\", \"description\": \"对锐利边缘进行平滑过渡处理，提升视觉真实感并优化光照反射；参数化倒角支持随曲率自动调整宽度，保持模型比例协调与拓扑均匀。\"}], \"summary\": \"参数化建模以数据关联为核心，每一步操作均保留可编辑参数，形成从草图到成品的完整闭环；该流程显著提升修改效率，适用于需要频繁调整的产品设计与硬表面建模场景。\", \"diagram_url\": \"\", \"background_image\": \"\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b7509910-de29-47aa-afbf-2a42d74096cb', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 0, NULL, '{\"page_id\": \"p01\", \"title\": \"封面：开启你的三维世界之门\", \"layout_id\": \"edu_cover\", \"has_image\": true, \"keywords\": [\"深蓝色科技感背景\", \"立体网格线框模型\", \"青绿色发光边框\", \"未来感光影效果\"], \"depends_on\": [], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"logical_page_id\": \"p01\", \"layout_variant\": \"b\", \"layout_archetype\": \"cover\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227505\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:46:24', 'edu_cover', '{\"title\": \"开启你的三维世界之门\", \"subtitle\": \"三维建模技术与产业应用实战课程。\", \"author\": \"智慧工程学院\", \"department\": \"数字化教研室\", \"date\": \"2024 年 5 月\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"cover\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('b9f4561e-3fb8-4da0-b063-8410e200a685', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 2, '导览', '{\"title\": \"目录与学习路线图：案例复盘\", \"points\": [\"问题与场景：解析低模布线混乱导致的动画拉伸痛点\", \"方案与执行：演示四边面重构与循环边优化的关键步骤\", \"结果与启示：对比优化前后渲染效率提升数据\", \"风险提示：警惕过度细分造成的面数冗余与性能瓶颈\"], \"part\": \"导览\"}', '{\"text\": \"目录与学习路线图：案例复盘\\n\\n页面文字：\\n- 问题背景：低模布线混乱导致动画拉伸严重，影响角色动作自然度。\\n- 方法动作：执行四边面重构并优化循环边，重塑模型基础拓扑结构。\\n- 结果启示：优化后渲染效率显著提升，为后续动画制作扫清障碍。\\n- 风险提示：需警惕过度细分造成的面数冗余与实时性能瓶颈问题。\", \"generated_at\": \"2026-03-09T03:39:36.940053\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/b9f4561e-3fb8-4da0-b063-8410e200a685_v1.png', 'COMPLETED', '2026-03-09 03:39:10', '2026-03-09 03:40:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bb266638-0b02-4a7c-913f-e6659b160195', 'b494fc12-8d48-4b4c-8717-9faa745d5f79', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"协作任务：团队分工绘制高精度贴图\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p10\"], \"must_cover\": [\"角色分工\", \"资产命名规范\", \"图层管理\", \"协作任务：团队分工绘制高精度贴图的核心概念与背景\", \"协作任务：团队分工绘制高精度贴图的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"协作任务：团队分工绘制高精度贴图的核心概念与背景\", \"协作任务：团队分工绘制高精度贴图的关键方法与执行要点\", \"协作任务：团队分工绘制高精度贴图的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\"}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-08 02:23:20', '2026-03-08 02:23:20', 'group_collab', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bc1e6cd0-04d8-4c13-96a5-7cbf885c54bd', '9b5d83ef-2600-4c3b-b852-00607680277d', 8, '应用价值', '{\"page_id\": \"p09\", \"title\": \"行业影响：重塑内容生产与工作流\", \"part\": \"应用价值\", \"points\": [\"自动生成文案、代码与视觉素材大幅提效，释放创意生产力\", \"个性化教育辅导与智能客服成为企业新标配，降低运营成本\", \"企业级应用正从概念实验走向规模化落地，重构核心业务流程\", \"人机协作模式发生根本性转变，AI 从辅助工具升级为决策伙伴\"]}', '{\"text\": \"页面标题：行业影响：重塑内容生产与工作流\\n\\n页面文字：\\n- 自动生成文案、代码与视觉素材大幅提效，全面释放了人类的创意生产力。\\n- 个性化教育辅导与智能客服成为企业新标配，有效降低了整体运营成本。\\n- 企业级应用正从概念实验走向规模化落地，正在重构核心业务流程与架构。\\n- 人机协作模式发生根本性转变，AI已从辅助工具升级为关键的决策合作伙伴。\", \"generated_at\": \"2026-03-09T08:14:14.916920\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/bc1e6cd0-04d8-4c13-96a5-7cbf885c54bd_v2.png', 'FAILED', '2026-03-09 08:13:51', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bc381352-713b-421a-b5d7-92cc71618af7', '7a4f3408-ca73-4a61-998e-174a92497610', 8, NULL, '{\"page_id\": \"p09\", \"title\": \"案例研讨：精密仪器外壳建模复盘\", \"layout_id\": \"case_discussion\", \"has_image\": true, \"keywords\": [\"高清产品渲染图\", \"爆炸视图分解\", \"工业蓝调背景\", \"问题聚焦气泡\", \"小组讨论引导区\"], \"depends_on\": [\"p07\"], \"must_cover\": [\"设计意图分析\", \"拓扑重构过程\", \"常见问题诊断\", \"优化方案对比\", \"案例研讨：精密仪器外壳建模复盘的核心概念与背景\"], \"promises_open\": [{\"promise_id\": \"pr_p09_1_6aa9e5d0\", \"text\": \"案例研讨：精密仪器外壳建模复盘的复盘与结果启示\", \"must_cover\": [\"案例复盘\", \"结果启示\"], \"target_page_ids\": [\"p17\"], \"is_hard\": true}], \"promises_close\": [\"pr_p01_2\"], \"points\": [\"案例研讨：精密仪器外壳建模复盘的核心概念与背景\", \"案例研讨：精密仪器外壳建模复盘的关键方法与执行要点\", \"案例研讨：精密仪器外壳建模复盘的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_2\"], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p09\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.266748\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'case_discussion', '{\"title\": \"案例研讨：精密仪器外壳建模复盘\", \"content\": [\"项目背景聚焦于一款高精密医疗仪器外壳，初始模型存在布线冗余导致细分后表面扭曲，且倒角处出现黑斑瑕疵。\", \"团队通过重构核心拓扑结构，优化支撑边分布并统一四边形面片，成功解决了形变问题并实现了工业级光滑渲染。\", \"此案例启示我们：优秀的硬表面建模不仅依赖工具，更在于对拓扑逻辑的深刻理解与严谨执行。\"], \"highlight\": \"拓扑重构是解决复杂曲面问题的关键钥匙。\", \"image\": {\"src\": \"\", \"alt\": \"高清产品渲染图展示精密仪器外壳，配合爆炸视图分解结构与工业蓝调背景，无文字无Logo\", \"position\": \"right\", \"width\": \"40%\"}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('be39a37a-ee5f-4ada-9c73-f3eebba25727', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 15, NULL, '{\"page_id\": \"p10\", \"title\": \"不同领域软件横向测评\", \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p09\"], \"must_cover\": [\"影视级需求\", \"游戏级需求\", \"建筑表现需求\", \"不同领域软件横向测评的核心概念与背景\", \"不同领域软件横向测评的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_job_1\", \"text\": \"就业市场具体数据分析\", \"must_cover\": [\"薪资水平\", \"人才缺口\"], \"target_page_ids\": [\"p26\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"不同领域软件横向测评的核心概念与背景\", \"不同领域软件横向测评的关键方法与执行要点\", \"不同领域软件横向测评的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p16\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T13:04:03.227904\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_tri_compare', '{\"title\": \"不同领域软件横向测评\", \"left\": {\"header\": \"测评核心概念\", \"content\": [\"不同领域软件横向测评在测评核心概念下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-book-reader\", \"text\": \"确立行业评估基线，明确工具能力边界。\", \"description\": \"解释确立行业评估基线，明确工具能力边界在测评核心概念维度下的意义。\"}, {\"icon\": \"fa-radar\", \"text\": \"量化性能资源消耗，识别技术债务风险。\", \"description\": \"解释量化性能资源消耗，识别技术债务风险在测评核心概念维度下的意义。\"}, {\"icon\": \"fa-project-diagram\", \"text\": \"分析跨平台 SOP 规范，确保流转安全。\", \"description\": \"解释分析跨平台 SOP 规范，确保流转安全在测评核心概念维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"综合评估预算目标，避免资源浪费。\", \"description\": \"解释综合评估预算目标，避免资源浪费在测评核心概念维度下的意义。\"}]}, \"right\": {\"header\": \"领域需求与执行\", \"content\": [\"不同领域软件横向测评在领域需求与执行下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-film\", \"text\": \"影视渲染精度优先，考察显存与通道支持。\", \"description\": \"解释影视渲染精度优先，考察显存与通道支持在领域需求与执行维度下的意义。\"}, {\"icon\": \"fa-gamepad\", \"text\": \"游戏实时交互优化，关注引擎导出格式。\", \"description\": \"解释游戏实时交互优化，关注引擎导出格式在领域需求与执行维度下的意义。\"}, {\"icon\": \"fa-drafting-compass\", \"text\": \"建筑光影真实感，侧重材质贴图解析力。\", \"description\": \"解释建筑光影真实感，侧重材质贴图解析力在领域需求与执行维度下的意义。\"}, {\"icon\": \"fa-wrench\", \"text\": \"建立参数基线测试，监控资产损耗情况。\", \"description\": \"解释建立参数基线测试，监控资产损耗情况在领域需求与执行维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('be8f4ee9-d936-4753-8cfc-9f8b5f407113', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 15, NULL, '{\"page_id\": \"p16\", \"title\": \"对比分析：区域光与IES光源的差异\", \"layout_id\": \"case_discussion\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p14\"], \"must_cover\": [\"区域光柔化特性\", \"IES投影真实性\", \"应用场景选择\", \"对比分析：区域光与IES光源的差异的核心概念与背景\", \"对比分析：区域光与IES光源的差异的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"对比分析：区域光与IES光源的差异的核心概念与背景\", \"对比分析：区域光与IES光源的差异的关键方法与执行要点\", \"对比分析：区域光与IES光源的差异的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"concept_explain\", \"layout_variant\": \"a\", \"logical_page_id\": \"p16\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928736\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'case_discussion', '{\"title\": \"对比分析：区域光与IES光源的差异\", \"content\": [\"区域光通过物理面积模拟柔化阴影，适合营造自然柔和的氛围，但缺乏细节投影；IES光源基于真实灯具配光曲线，能精准还原复杂光影纹理，如百叶窗或格栅投影。\", \"在角色特写场景中，区域光可消除生硬阴影边界；而在建筑可视化中，IES光源则能真实再现室内灯光的层次与质感，二者需根据项目需求灵活搭配使用。\"], \"highlight\": \"区域光重氛围，IES光源重真实投影纹理。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"concept_explain\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('bf873512-9b04-44dc-ac6b-435772d7e766', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 23, NULL, '{\"page_id\": \"p18\", \"title\": \"必备辅助工具与资源包\", \"layout_id\": \"edu_core_hub\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p17\"], \"must_cover\": [\"插件库推荐\", \"素材网站\", \"练习源文件\", \"必备辅助工具与资源包的核心概念与背景\", \"必备辅助工具与资源包的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"必备辅助工具与资源包的核心概念与背景\", \"必备辅助工具与资源包的关键方法与执行要点\", \"必备辅助工具与资源包的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p24\", \"layout_variant\": \"b\", \"layout_archetype\": \"core_model\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T12:17:13.187719\"}', NULL, 'FAILED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_core_hub', '{\"title\": \"必备辅助工具与资源包\", \"content\": [\"集成专业插件库，内置拓扑清理与 UV 拆分脚本，大幅缩短基础建模耗时。\", \"精选素材网站清单，收录高清 HDR 环境与 PBR 材质包，直接用于项目实战。\", \"配套练习源文件，包含分层工程文档，支持逆向拆解学习资产管线逻辑。\", \"常用软件版本管理指南，明确插件兼容性说明，规避环境配置冲突风险。\"], \"highlight\": \"善用工具而非依赖，核心是理解底层逻辑。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"core_model\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c09ba23e-73b5-4b87-ad20-bfd2b60b41a1', '8869b00d-4474-4021-b49f-8c3f51c87140', 1, NULL, '{\"title\": \"核心内容\", \"points\": [\"技术原理\"]}', '{\"text\": \"页面标题：核心内容\\n页面文字：\\n- 新核心内容描述\", \"generated_at\": \"2026-03-08T14:30:24.135638\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-08 06:30:24', '2026-03-08 14:30:24', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c1720588-14a8-46e3-b5b0-cb9ee6a94c1a', '6c250523-422a-46f3-a1f1-42e82424897c', 1, NULL, '{\"title\": \"3D建模入门：从原理到实战：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"toc_academic\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p02\", \"depends_on\": [\"p01\"], \"must_cover\": [], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"toc\", \"layout_variant\": \"a\", \"logical_page_id\": \"p02\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286681\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'toc_academic', '{\"title\": \"课程目录概览\", \"items\": [{\"index\": 1, \"text\": \"第一章：3D空间基础与坐标系统。\"}, {\"index\": 2, \"text\": \"第二章：多边形建模核心逻辑与拓扑规范。\"}, {\"index\": 3, \"text\": \"第三章：UV展开策略与纹理映射原理。\"}, {\"index\": 4, \"text\": \"第四章：材质节点系统与物理渲染(PBR)。\"}, {\"index\": 5, \"text\": \"第五章：灯光布置与全局光照计算。\"}, {\"index\": 6, \"text\": \"第六章：经典案例复盘——低模角色制作全流程。\"}], \"background_image\": null, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"toc\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c1989cbd-2320-43dc-bc4f-05cc2b2d46de', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 9, '视觉表现', '{\"page_id\": \"p08\", \"title\": \"灯光布置与渲染引擎初探\", \"part\": \"视觉表现\", \"points\": [\"三点布光法（主光、补光、轮廓光）构建基础立体感与层次\", \"区域光精准照明结合HDRI环境光模拟真实物理光照反射\", \"Cycles路径追踪追求极致画质，Eevee实时引擎兼顾效率预览\", \"利用渲染器特性优化噪点控制与采样设置提升出图速度\"]}', '{\"text\": \"页面标题：灯光布置与渲染引擎初探\\n\\n页面文字：\\n- 采用三点布光法构建主光、补光与轮廓光，奠定场景基础立体感与丰富层次。\\n- 结合区域光精准照明与HDRI环境光，模拟真实物理光照反射以增强沉浸体验。\\n- 依据需求在Cycles路径追踪的极致画质与Eevee实时引擎的高效预览间灵活切换。\\n- 利用渲染器特性优化噪点控制策略与采样设置，显著提升最终出图速度与质量。\", \"generated_at\": \"2026-03-09T03:39:38.191747\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/c1989cbd-2320-43dc-bc4f-05cc2b2d46de_v1.png', 'COMPLETED', '2026-03-09 03:39:20', '2026-03-09 03:47:18', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c52907f8-8567-497b-952f-95386dd3df9b', '5eaa269b-efa0-48a1-a72c-467d905d6bf4', 7, NULL, '{\"page_id\": \"p08\", \"title\": \"协作任务：优化复杂硬表面模型的布线\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p06\"], \"must_cover\": [\"任务分工说明\", \"优化标准清单\", \"交付格式要求\", \"协作任务：优化复杂硬表面模型的布线的核心概念与背景\", \"协作任务：优化复杂硬表面模型的布线的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_case_01\"], \"points\": [\"协作任务：优化复杂硬表面模型的布线的核心概念与背景\", \"协作任务：优化复杂硬表面模型的布线的关键方法与执行要点\", \"协作任务：优化复杂硬表面模型的布线的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_case_01\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p08\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_case_01\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:44:29.928425\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:31:56', '2026-03-08 02:44:30', 'group_collab', '{\"title\": \"协作任务：优化复杂硬表面模型的布线\", \"subtitle\": \"从理论到实战：团队协同解决拓扑难题。\", \"bullets\": [{\"icon\": \"fa-users\", \"text\": \"任务分工说明。\", \"description\": \"每组需指定拓扑师、动画测试员与质检员，明确各自在建模、变形验证及标准核对中的职责。\"}, {\"icon\": \"fa-list-check\", \"text\": \"优化标准清单。\", \"description\": \"严格检查所有转角处是否存在N-gon，确认支撑环密度是否满足细分曲面要求，保证流动方向符合力学逻辑。\"}, {\"icon\": \"fa-file-export\", \"text\": \"交付格式要求。\", \"description\": \"提交包含原始工程文件、高模细节层及低模拓扑图的压缩包，附带变形测试视频片段以证明布线有效性。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见误区警示。\", \"description\": \"严禁为了美观强行合并面片导致极点堆积，避免在非受力区域随意使用三角面破坏布线流向。\"}], \"keyTakeaway\": \"团队协作的核心在于统一拓扑标准，确保每个模型都能经受住动态变形的严苛考验。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c5442699-fd98-4f6c-8b58-bf1f8c4c128a', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 20, NULL, '{\"page_id\": \"p21\", \"title\": \"致谢\", \"layout_id\": \"ending_field\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p19\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"layout_archetype\": \"summary_reflection\", \"layout_variant\": \"b\", \"logical_page_id\": \"p21\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832698\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-09 07:07:33', 'ending_field', '{\"title\": \"致谢\", \"subtitle\": \"感谢每一位探索者。\", \"contact\": \"联系方式：educator@algo-mastery.edu\", \"reflection_blocks\": [{\"title\": \"反思维度：核心脉络\", \"items\": [\"从问题识别到工业级落地的完整闭环\", \"场景选择、边界处理与稳定性优化的串联思考\"]}, {\"title\": \"反思维度：技能沉淀\", \"items\": [\"掌握不稳定快排与稳定归并的实战差异\", \"建立对数据流动本质与物理类比的直观认知\"]}], \"closing\": \"算法之美，不仅在于解决当下，更在于构建未来的逻辑基石。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('c5f30792-dc15-4a01-a0a6-9de680bf6d23', '2210a36d-b61a-453a-83ee-86edc9925e6a', 12, NULL, '{\"title\": \"高级案例：硬表面机械零件：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"case_study\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p13\", \"depends_on\": [\"p12\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"logical_page_id\": \"p13\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647742\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'case_study', '{\"title\": \"典型案例分析\", \"scenario\": \"工业级硬表面机械零件高精度建模项目，涉及布尔运算与材质渲染全流程。\", \"challenge\": \"布尔运算后边缘锐利度不足及材质反射失真，导致视觉真实感严重缺失。\", \"points\": [{\"title\": \"拓扑重构策略\", \"description\": \"消除非流形几何错误，通过手动布线保留关键硬边特征以维持结构完整性。\"}, {\"title\": \"细节精度控制\", \"description\": \"增加切角厚度与倒角参数，精细控制光影过渡与金属反射效果的一致性。\"}], \"conclusion\": \"模型布线决定拓扑质量，细节精度与物理参数共同决定最终渲染的真实感与稳定性。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
