INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cbc948f9-f9b8-4ce9-82bb-55ff7ae4f340', '766dd313-1e7e-43f8-b4e9-3ca4b9e71dd6', 10, NULL, '{\"page_id\": \"p11\", \"title\": \"性能优化策略对比\", \"layout_id\": \"edu_tri_compare\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"高精度模型局限\", \"实时渲染要求\", \"移动端适配方案\", \"性能优化策略对比的核心概念与背景\", \"性能优化策略对比的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [\"pr_p08_1\"], \"points\": [\"性能优化策略对比的核心概念与背景\", \"性能优化策略对比的关键方法与执行要点\", \"性能优化策略对比的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p08_1\"]}', NULL, NULL, 'OUTLINE_GENERATED', '2026-03-06 09:45:17', '2026-03-06 09:45:17', 'edu_tri_compare', NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cd2570e1-e28d-4894-83cf-27e70d4a3c83', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 5, '理论基石', '{\"title\": \"核心概念：多边形与拓扑结构：案例复盘\", \"points\": [\"问题与场景：低模角色在变形时出现严重网格撕裂，暴露布线冗余与流向错误\", \"方案与执行：采用四边面重构策略，沿肌肉走向重新规划环形布线以优化形变\", \"结果与启示：模型关节弯曲流畅自然，验证了规范拓扑对后续雕刻与绑定的决定性作用\", \"风险提示：盲目追求面数均匀而忽视功能分区，将导致后续细分曲面渲染异常\"], \"part\": \"理论基石\"}', '{\"text\": \"页面标题：核心概念：多边形与拓扑结构：案例复盘\\n\\n页面文字：\\n- 问题背景显示低模角色变形时出现严重撕裂，暴露出布线冗余及流向错误的致命缺陷。\\n- 执行方案采用四边面重构策略，沿肌肉走向重新规划环形布线以彻底优化形变表现。\\n- 结果启示表明关节弯曲变得流畅自然，验证了规范拓扑对后续雕刻与绑定环节的决定性作用。\\n- 风险提示盲目追求面数均匀而忽视功能分区，将导致细分曲面渲染出现不可控的视觉异常。\", \"generated_at\": \"2026-03-09T03:39:37.774095\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/cd2570e1-e28d-4894-83cf-27e70d4a3c83_v2.png', 'COMPLETED', '2026-03-09 03:39:15', '2026-03-09 03:44:32', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cdb00019-e1bf-4856-ba79-f924a4845955', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 12, '收尾', '{\"page_id\": \"p13\", \"title\": \"答疑互动与下一步行动\", \"part\": \"收尾\", \"points\": [\"开放现场提问，针对性解决建模卡点与软件配置难题\", \"发布课后实战任务清单，包含低模角色与硬表面场景练习\", \"引导加入专属学习社群，获取持续更新的素材包与行业资讯\", \"分享优秀学员案例库，提供从作品打磨到接单对接的完整路径\"]}', '{\"text\": \"页面标题：答疑互动与下一步行动\\n\\n页面文字：\\n- 开放现场提问环节，针对性解决建模拓扑卡点与软件配置难题。\\n- 发布课后实战任务清单，包含低模角色塑造与硬表面场景构建练习。\\n- 引导加入专属学习社群，获取持续更新的素材包与前沿行业资讯。\\n- 分享优秀学员案例库，提供从作品打磨细节到接单对接的完整路径。\", \"generated_at\": \"2026-03-09T03:39:36.946440\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/cdb00019-e1bf-4856-ba79-f924a4845955_v1.png', 'COMPLETED', '2026-03-09 03:39:25', '2026-03-09 03:48:35', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('cfc3c0b8-6178-45e7-a8c2-660ff5347343', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 4, '第一阶段', '{\"title\": \"第一次浪潮：专家系统的崛起与瓶颈：案例复盘\", \"points\": [\"核心矛盾：MYCIN系统需解决医疗诊断中复杂规则难以穷举且依赖人类专家经验的难题\", \"关键执行：构建包含500条IF-THEN规则的推理机，通过不确定性推理模拟医生决策逻辑\", \"显著成果：在特定细菌感染诊断任务中准确率媲美资深专家，验证了知识工程的可行性\", \"致命瓶颈：规则库维护成本极高，缺乏通用性导致无法迁移至其他领域，引发AI寒冬\"], \"part\": \"第一阶段\"}', '{\"text\": \"页面标题：第一次浪潮：专家系统的崛起与瓶颈：案例复盘\\n\\n页面文字：\\n- 背景上，MYCIN需解决医疗诊断中复杂规则难以穷举且依赖人类经验的难题。\\n- 方法上，构建包含五百条IF-THEN规则的推理机，通过不确定性模拟医生决策。\\n- 结果上，特定细菌感染诊断准确率媲美资深专家，验证了知识工程的可行性。\\n- 启示在于规则库维护成本极高且缺乏通用性，最终引发AI技术发展的寒冬。\", \"generated_at\": \"2026-03-09T08:54:47.141699\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:25', '2026-03-09 08:54:49', NULL, NULL);
