INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d3fef520-8da5-4363-9d25-4c5925856b8b', '8c3c7887-392d-4fe3-b52e-98cbface7e1f', 26, NULL, '{\"page_id\": \"p21\", \"title\": \"课程总结与行动号召\", \"layout_id\": \"edu_summary\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p20\"], \"must_cover\": [], \"promises_open\": [], \"promises_close\": [], \"points\": [], \"required_close_promise_ids\": [], \"logical_page_id\": \"p27\", \"layout_variant\": \"b\", \"layout_archetype\": \"summary_reflection\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-06T12:17:13.187775\"}', NULL, 'FAILED', '2026-03-06 10:12:18', '2026-03-08 01:16:23', 'edu_summary', '{\"title\": \"致谢与启程\", \"reflection_blocks\": [{\"title\": \"技能维度\", \"items\": [\"模型精度优化\", \"规范工作流程\"]}, {\"title\": \"职业维度\", \"items\": [\"作品集打磨\", \"面试技巧准备\"]}, {\"title\": \"学习维度\", \"items\": [\"跟进技术迭代\", \"积极参与社区\"]}], \"closing\": \"以匠心致初心，在数字世界创造无限价值。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"summary_reflection\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d658cfdc-daac-48c0-8fa2-753b5b4252c3', '9b5d83ef-2600-4c3b-b852-00607680277d', 3, 'ChatGPT篇', '{\"page_id\": \"p04\", \"title\": \"进阶之路：OpenAI的迭代策略\", \"part\": \"ChatGPT篇\", \"points\": [\"从GPT-3.5到GPT-4，通过思维链（CoT）与推理微调实现逻辑能力的质变\", \"插件系统与代码解释器将单一对话工具升级为具备执行力的智能工作流\", \"面对竞争压力加速多模态整合，原生支持图像理解与生成能力\", \"持续优化响应速度与上下文窗口，平衡性能成本以拓展企业级应用\"]}', '{\"text\": \"页面标题：进阶之路：OpenAI的迭代策略\\n\\n页面文字：\\n- GPT系列从3.5演进至4，通过思维链与推理微调实现了逻辑能力的质的飞跃。\\n- 插件系统与代码解释器将单一对话工具升级为具备实际执行力的智能工作流。\\n- 面对激烈竞争加速多模态整合，原生支持图像理解与生成能力以拓展应用场景。\\n- 持续优化响应速度与上下文窗口，在平衡性能成本的同时大力拓展企业级应用。\", \"generated_at\": \"2026-03-09T08:14:15.317243\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/d658cfdc-daac-48c0-8fa2-753b5b4252c3_v1.png', 'FAILED', '2026-03-09 08:13:42', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d6ed893c-9cdb-42b1-b5ca-9b5a1bfcac5b', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 11, '避坑指南', '{\"page_id\": \"p10\", \"title\": \"常见错误排查与优化建议\", \"part\": \"避坑指南\", \"points\": [\"利用网格诊断工具快速定位并修复非流形几何体，确保模型水密性\", \"通过代理低模预览与LOD技术平衡面数，解决渲染卡顿与内存溢出问题\", \"规范UV接缝布局与拉伸检查，消除纹理变形并提升贴图清晰度\"]}', '{\"text\": \"页面标题：常见错误排查与优化建议\\n\\n页面文字：\\n- 针对非流形几何体导致的渲染错误，利用网格诊断工具快速定位并修复确保水密性。\\n- 面对大场景卡顿痛点，通过代理低模预览与LOD技术平衡面数，有效解决内存溢出。\\n- 规范UV接缝布局并检查拉伸情况，彻底消除纹理变形，大幅提升贴图清晰度表现。\\n- 掌握上述排查技巧将助您规避制作陷阱，从容应对各类高难度项目挑战。\", \"generated_at\": \"2026-03-09T03:39:38.191764\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/d6ed893c-9cdb-42b1-b5ca-9b5a1bfcac5b_v1.png', 'COMPLETED', '2026-03-09 03:39:24', '2026-03-09 03:48:15', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d8cb99f8-0530-468d-b08c-743138936704', '9b5d83ef-2600-4c3b-b852-00607680277d', 6, 'Gemini篇', '{\"page_id\": \"p06\", \"title\": \"生态优势：Google Gemini的多模态原生设计\", \"part\": \"Gemini篇\", \"points\": [\"原生多模态架构从训练阶段即融合文本、图像、音频与视频，实现跨模态深度理解而非简单拼接\", \"依托Google全球海量数据资源，构建起端侧设备与云端算力无缝协同的完整生态系统\", \"推出Ultra、Pro、Nano三级模型矩阵，精准匹配高算力推理、通用办公及移动端实时交互场景\", \"通过Android系统与Workspace套件深度集成，将AI能力无缝嵌入用户日常数字工作流\"]}', '{\"text\": \"页面标题：生态优势：Google Gemini的多模态原生设计\\n\\n页面文字：\\n- 原生多模态架构从训练阶段即融合文本、图像、音频与视频，实现跨模态深度理解而非简单拼接。\\n- 依托Google全球海量数据资源，构建起端侧设备与云端算力无缝协同的完整生态系统。\\n- 推出Ultra、Pro、Nano三级模型矩阵，精准匹配高算力推理、通用办公及移动端实时交互场景。\\n- 通过Android系统与Workspace套件深度集成，将AI能力无缝嵌入用户日常数字工作流。\", \"generated_at\": \"2026-03-09T08:14:14.916891\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/d8cb99f8-0530-468d-b08c-743138936704_v1.png', 'FAILED', '2026-03-09 08:13:48', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('d91d09f7-ca30-4832-8ce6-e641e8a19307', '14c0f24c-10e7-4309-a927-d9db1066897c', 9, NULL, '{\"page_id\": \"p10\", \"title\": \"硬表面建模：布尔运算与倒角\", \"layout_id\": \"infographic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p08\"], \"must_cover\": [\"布尔切割流程\", \"倒角厚度控制\", \"非破坏性编辑\", \"硬表面建模：布尔运算与倒角的核心概念与背景\", \"硬表面建模：布尔运算与倒角的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"硬表面建模：布尔运算与倒角的核心概念与背景\", \"硬表面建模：布尔运算与倒角的关键方法与执行要点\", \"硬表面建模：布尔运算与倒角的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p10\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773922\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'infographic_flow', '{\"title\": \"硬表面建模：布尔运算与倒角\", \"subtitle\": \"从非破坏性编辑到完美拓扑的构建逻辑。\", \"bullets\": [{\"icon\": \"fa-cube\", \"text\": \"布尔切割流程标准化。\", \"description\": \"建立‘先粗切后精修’的非破坏性工作流，利用修改器堆栈保留原始几何体，避免直接合并导致的网格错误。\"}, {\"icon\": \"fa-arrows-alt-h\", \"text\": \"倒角厚度智能控制。\", \"description\": \"根据模型最终渲染比例设定倒角宽度，过薄会导致光照伪影，过厚则破坏硬表面锐利感，需保持参数化关联。\"}, {\"icon\": \"fa-layer-group\", \"text\": \"非破坏性编辑策略。\", \"description\": \"全程使用修改器（Modifier）而非应用操作，确保在遇到拓扑问题时可随时回溯至布尔运算前的状态进行修复。\"}], \"keyTakeaway\": \"掌握非破坏性布尔与倒角是解决硬表面拓扑撕裂、保障流体动力学计算路径完整性的核心前提。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('da735b07-ecf9-4608-8204-0b7527288d3f', '6c250523-422a-46f3-a1f1-42e82424897c', 11, NULL, '{\"title\": \"实战演练：从零开始构建一个立方体：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"academic_narrative\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p12\", \"depends_on\": [\"p11\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p12\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.286966\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 06:26:06', 'academic_narrative', '{\"title\": \"实战演练：从零开始构建一个立方体：案例复盘\", \"narrative\": [\"本案例的核心矛盾在于初学者往往混淆‘创建对象’与‘建立工作流’的概念，误以为点击生成按钮即完成建模任务，忽视了视图导航与坐标系统的基础重要性。执行阶段的关键动作包括：首先确认软件界面布局是否符合个人习惯，其次通过键盘快捷键而非鼠标菜单调用工具以提升效率，最后必须在操作前明确保存策略以避免数据丢失。\", \"结果启示表明，即使是简单的立方体构建，也蕴含着完整的工程思维：从环境配置到数据持久化，每一步都影响后续复杂模型的扩展性。风险提示在于，若未在初始阶段规范命名与目录结构，后期资产整合将面临巨大的管理成本，这直接关联到后续完整工作流的顺利展开。\"], \"margin_notes\": [{\"title\": \"关键决策依据\", \"content\": \"选择保存格式时需考虑兼容性：Blender默认.blend保留所有编辑历史，Maya的.ma/.mb格式则需权衡场景文件大小与跨软件传输需求。\"}, {\"title\": \"可复用经验\", \"content\": \"养成‘操作前思考、操作中记录、完成后归档’的习惯，是应对未来复杂项目管线的基础能力。\"}], \"pull_quote\": \"伟大的模型始于对基础操作的敬畏与规范，而非对复杂功能的盲目追求。\", \"background_image\": \"https://images.unsplash.com/photo-1633462972861-6d5c6f2b5e5f?auto=format&fit=crop&q=80&w=2070\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('da918e49-365b-4c08-b17a-14e9c8af7268', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 19, NULL, '{\"page_id\": \"p20\", \"title\": \"结语：算法之美在于逻辑\", \"layout_id\": \"portfolio_industry\", \"has_image\": true, \"keywords\": [\"意境深远远景\", \"核心愿景表达\", \"深木棕与医疗白融合\", \"电影感收束\", \"留白艺术\"], \"depends_on\": [\"p18\"], \"must_cover\": [\"课程总结升华\", \"未来展望\", \"结语：算法之美在于逻辑的核心概念与背景\", \"结语：算法之美在于逻辑的关键方法与执行要点\", \"结语：算法之美在于逻辑的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [\"pr_p01_1\", \"pr_p03_1\", \"pr_p05_1\", \"pr_p07_1\", \"pr_p10_1\"], \"points\": [\"结语：算法之美在于逻辑的核心概念与背景\", \"结语：算法之美在于逻辑的关键方法与执行要点\", \"结语：算法之美在于逻辑的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p01_1\", \"pr_p03_1\", \"pr_p05_1\", \"pr_p07_1\", \"pr_p10_1\"], \"layout_archetype\": \"generic_content\", \"layout_variant\": \"a\", \"logical_page_id\": \"p20\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p01_1\", \"pr_p03_1\", \"pr_p05_1\", \"pr_p07_1\", \"pr_p10_1\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832659\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'portfolio_industry', '{\"title\": \"结语：算法之美在于逻辑\", \"subtitle\": \"从交换机制到物理类比的深度共鸣。\", \"items\": [{\"image_src\": \"https://example.com/algorithm-logic-aesthetic.jpg\", \"title\": \"逻辑的秩序之美\", \"description\": \"回顾从冒泡排序的交换过程、比较机制，到数据流动的物理类比，最终在双重循环的精密运作中展现算法的严谨逻辑。\", \"tags\": [\"逻辑闭环\", \"深度解析\"]}, {\"image_src\": \"https://example.com/performance-comparison.jpg\", \"title\": \"性能的极致博弈\", \"description\": \"对比原始版与优化版的实测结果，在最坏情况与最好情况的动态变化中，体会优化技巧如何重塑算法的生命力。\", \"tags\": [\"性能实测\", \"优化技巧\"]}, {\"image_src\": \"https://example.com/future-vision.jpg\", \"title\": \"未来的无限可能\", \"description\": \"课程虽止，探索不止。将现场观测视角延伸至更广阔的数据世界，用伪代码与循环结构构建通往智能时代的桥梁。\", \"tags\": [\"未来展望\", \"愿景归宿\"]}], \"layout\": \"grid\", \"background_image\": \"https://example.com/wooden-white-background.jpg\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('dbcc41b8-ce7a-4ea3-8160-922cb4f07f93', '2210a36d-b61a-453a-83ee-86edc9925e6a', 13, NULL, '{\"page_id\": \"p14\", \"title\": \"网格优化与性能限制理论\", \"layout_id\": \"theory_explanation\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"三角面计数公式\", \"绘制调用优化阈值\", \"网格优化与性能限制理论的核心概念与背景\", \"网格优化与性能限制理论的关键方法与执行要点\", \"网格优化与性能限制理论的应用场景与注意事项\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"网格优化与性能限制理论的核心概念与背景\", \"网格优化与性能限制理论的关键方法与执行要点\", \"网格优化与性能限制理论的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"logical_page_id\": \"p14\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T06:30:50.647755\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 06:24:26', '2026-03-07 07:17:35', 'theory_explanation', '{\"title\": \"理论推导\", \"theory\": [\"网格顶点与面片数量直接决定渲染负载与实时帧率的平衡点。\", \"绘制调用次数过多会导致 GPU 指令缓冲区溢出引起系统卡顿。\"], \"formulas\": [{\"latex\": \"C_{tri} = 2 \\\\cdot N_{verts} - 4\", \"explanation\": \"凸多面体三角面计数欧拉公式近似值，用于估算三角面总数上限。\"}, {\"latex\": \"T_{budget} = \\\\frac{1}{FPS_{target}}\", \"explanation\": \"单次绘制调用耗时预算取决于目标帧率，不可超标以免影响流畅度。\"}], \"references\": [\"《计算机图形学原理与实践》第三版\", \"NVIDIA 官方图形管线优化指南\"], \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"generic_content\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('dd5e81fa-70f1-4c86-8e64-14430df4480b', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 5, '第二阶段', '{\"page_id\": \"p05\", \"title\": \"转折点：互联网兴起与统计学习回归\", \"part\": \"第二阶段\", \"points\": [\"互联网普及催生海量数据，为算法训练提供关键燃料\", \"范式从“硬编码规则”彻底转向“数据驱动的概率模型”，突破专家系统瓶颈\", \"支持向量机（SVM）与随机森林等统计学习方法成为当时主流工具\", \"机器学习重新成为研究热点，AI 技术进入复苏与快速迭代期\"]}', '{\"text\": \"页面标题：转折点：互联网兴起与统计学习回归\\n\\n页面文字：\\n- 互联网普及催生了海量数据资源，为新一代算法训练提供了关键燃料支撑。\\n- 研究范式从硬编码规则彻底转向数据驱动的概率模型，有效突破专家瓶颈。\\n- 支持向量机与随机森林等统计学习方法成为当时学术界的主流工具与标准。\\n- 机器学习重新成为热点，推动AI技术进入复苏阶段并开启快速迭代新篇章。\", \"generated_at\": \"2026-03-09T08:54:47.141701\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:26', '2026-03-09 08:54:49', NULL, NULL);
