INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('e4a7f301-613d-46a0-a6b4-d939f73eabbd', '6c250523-422a-46f3-a1f1-42e82424897c', 20, NULL, '{\"page_id\": \"p21\", \"title\": \"课程总结与知识图谱回顾\", \"layout_id\": \"key_takeaways\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p17\"], \"must_cover\": [\"核心概念串联\", \"技能树梳理\", \"常见误区提醒\", \"下一步行动指南\", \"课程总结与知识图谱回顾的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [\"pr_p16_1_630fbd9d\", \"pr_p02_1\", \"pr_p02_2\"], \"points\": [\"课程总结与知识图谱回顾的核心概念与背景\", \"课程总结与知识图谱回顾的关键方法与执行要点\", \"课程总结与知识图谱回顾的应用场景与注意事项\"], \"required_close_promise_ids\": [\"pr_p16_1_630fbd9d\", \"pr_p02_1\", \"pr_p02_2\"], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p21\"}', '{\"continuity\": {\"closed_promise_ids\": [\"pr_p16_1_630fbd9d\", \"pr_p02_1\", \"pr_p02_2\"], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T06:26:06.287290\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 06:24:11', '2026-03-08 14:27:25', 'key_takeaways', '{\"title\": \"课程总结与知识图谱回顾\", \"subtitle\": \"核心概念串联与技能树全景梳理。\", \"bullets\": [{\"icon\": \"fa-link\", \"text\": \"核心概念串联。\", \"description\": \"从拓扑结构定义出发，经UV展开映射、动态雕刻细化，最终通过置换烘焙实现低模高显，形成完整工作流闭环。\"}, {\"icon\": \"fa-sitemap\", \"text\": \"技能树梳理。\", \"description\": \"掌握布线规则与法线控制是基础；UV岛布局与接缝优化是关键；雕刻笔刷与平滑组应用是进阶；烘焙参数调优是实战核心。\"}, {\"icon\": \"fa-exclamation-triangle\", \"text\": \"常见误区提醒。\", \"description\": \"避免过度依赖自动工具而忽视手动调整；忽略法线方向导致光照错误；未检查自相交引发渲染崩溃。\"}, {\"icon\": \"fa-arrow-right\", \"text\": \"下一步行动指南。\", \"description\": \"立即实践低模高模置换烘焙全流程，复现课程案例；参与社区挑战赛；阅读进阶论文深化理论理解。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"承诺事项闭环。\", \"description\": \"已涵盖案例复盘（pr_p16_1_630fbd9d）、拓扑原则拆解（pr_p02_1）及完整工作流展示（pr_p02_2），确保知识体系无遗漏。\"}], \"keyTakeaway\": \"本课程构建了从理论基础到工程实践的完整知识图谱，强调规范操作与问题预判，助力学员高效产出影视级实时渲染资产。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
