INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ea355567-a451-4ada-82ef-d1c6db3b891c', '7a4f3408-ca73-4a61-998e-174a92497610', 12, NULL, '{\"page_id\": \"p13\", \"title\": \"互动测验：材质属性匹配挑战\", \"layout_id\": \"quiz_interaction\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p11\"], \"must_cover\": [\"金属度/粗糙度测试\", \"法线贴图识别\", \"环境光遮蔽效果\", \"互动测验：材质属性匹配挑战的核心概念与背景\", \"互动测验：材质属性匹配挑战的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"互动测验：材质属性匹配挑战的核心概念与背景\", \"互动测验：材质属性匹配挑战的关键方法与执行要点\", \"互动测验：材质属性匹配挑战的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p13\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267086\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:25', 'quiz_interaction', '{\"title\": \"互动测验：材质属性匹配挑战\", \"subtitle\": \"基于UV展开与纹理映射的实战检验。\", \"bullets\": [{\"icon\": \"fa-microchip\", \"text\": \"金属度与粗糙度辨析。\", \"description\": \"在复杂光照环境下，快速识别高反光表面的微细划痕与氧化层差异，判断PBR参数中的Metallic值是否准确。\"}, {\"icon\": \"fa-cubes\", \"text\": \"法线贴图深度感知。\", \"description\": \"通过观察表面凹凸阴影的变化趋势，反推法线贴图的强度设置，判断细节雕刻的合理性。\"}, {\"icon\": \"fa-eye\", \"text\": \"环境光遮蔽效果验证。\", \"description\": \"检查模型缝隙、角落处的接触阴影是否自然过渡，评估AO贴图对空间深度的贡献度。\"}, {\"icon\": \"fa-check-circle\", \"text\": \"材质属性匹配逻辑。\", \"description\": \"综合金属度、粗糙度、法线与AO四项指标，构建完整的材质视觉特征库，实现快速分类匹配。\"}], \"keyTakeaway\": \"掌握多参数协同分析方法，是提升材质还原度与制作效率的关键核心。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eb0fa5ec-ddc0-4efe-bcdc-2f51938ec9da', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 1, '导览', '{\"page_id\": \"p02\", \"title\": \"目录与学习路线图\", \"part\": \"导览\", \"points\": [\"主流建模软件对比：Blender、Maya与C4D的选型策略\", \"三维基石解析：从多边形拓扑到UV展开的核心逻辑\", \"实战路径指引：硬表面与有机生物案例全流程拆解\", \"进阶方向规划：渲染工作流与行业资源生态概览\"]}', '{\"text\": \"目录与学习路线图\\n\\n页面文字：\\n- 主流建模软件对比：Blender、Maya与C4D的选型策略。\\n- 三维基石解析：从多边形拓扑到UV展开的核心逻辑。\\n- 实战路径指引：硬表面与有机生物案例全流程拆解。\\n- 进阶方向规划：渲染工作流与行业资源生态概览。\", \"generated_at\": \"2026-03-09T03:39:36.940051\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/eb0fa5ec-ddc0-4efe-bcdc-2f51938ec9da_v1.png', 'COMPLETED', '2026-03-09 03:39:09', '2026-03-09 03:40:07', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('eb34e93e-9768-467b-b5ce-00e249c32f8d', 'dca4965c-6173-4908-ae52-ec6bb57c9dc1', 13, NULL, '{\"title\": \"实战演练：不同场景下的选择：案例复盘\", \"points\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"layout_id\": \"case_before_after\", \"has_image\": false, \"keywords\": [], \"page_id\": \"p14\", \"depends_on\": [\"p13\"], \"must_cover\": [\"问题与场景：案例要解决的核心矛盾\", \"方案与执行：关键动作与决策依据\", \"结果与启示：可复用经验与风险提示\"], \"promises_open\": [], \"required_close_promise_ids\": [], \"promises_close\": [], \"layout_archetype\": \"data_metrics\", \"layout_variant\": \"a\", \"logical_page_id\": \"p14\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T07:27:21.832334\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 07:25:54', '2026-03-08 07:27:22', 'case_before_after', '{\"title\": \"案例复盘：从混乱到有序的进阶之路\", \"left\": {\"header\": \"问题与场景：核心矛盾\", \"content\": [\"实战演练：不同场景下的选择：案例复盘在问题与场景：核心矛盾下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-exclamation-triangle\", \"text\": \"无序数据流导致系统响应迟滞，用户体验严重受损。\", \"description\": \"解释无序数据流导致系统响应迟滞，用户体验严重受损。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-balance-scale\", \"text\": \"传统全量遍历无法识别已排序区间，造成大量无效计算。\", \"description\": \"解释传统全量遍历无法识别已排序区间，造成大量无效计算。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-database\", \"text\": \"关键业务数据存在重复值，需严格保持原有相对顺序。\", \"description\": \"解释关键业务数据存在重复值，需严格保持原有相对顺序。在问题与场景：核心矛盾维度下的意义。\"}, {\"icon\": \"fa-clock\", \"text\": \"实时性要求极高，O(n²) 的原始算法无法满足时效标准。\", \"description\": \"解释实时性要求极高，O(n²) 的原始算法无法满足时效标准。在问题与场景：核心矛盾维度下的意义。\"}]}, \"right\": {\"header\": \"方案与结果：决策与启示\", \"content\": [\"实战演练：不同场景下的选择：案例复盘在方案与结果：决策与启示下的核心结论与适用条件。\"], \"bullets\": [{\"icon\": \"fa-check-circle\", \"text\": \"引入标志位 flag 监测交换状态，无变动即立即终止循环。\", \"description\": \"解释引入标志位 flag 监测交换状态，无变动即立即终止循环。在方案与结果：决策与启示维度下的意义。\"}, {\"icon\": \"fa-chart-line\", \"text\": \"实测平均耗时降低 65%，在部分有序数据下接近 O(n)。\", \"description\": \"解释实测平均耗时降低 65%，在部分有序数据下接近 O(n)。在方案与结果：决策与启示维度下的意义。\"}, {\"icon\": \"fa-shield-alt\", \"text\": \"成功保留重复元素的原始顺序，满足金融级稳定性需求。\", \"description\": \"解释成功保留重复元素的原始顺序，满足金融级稳定性需求。在方案与结果：决策与启示维度下的意义。\"}, {\"icon\": \"fa-lightbulb\", \"text\": \"经验表明：针对特定数据特征定制终止条件是关键优化点。\", \"description\": \"解释经验表明：针对特定数据特征定制终止条件是关键优化点。在方案与结果：决策与启示维度下的意义。\"}]}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"data_metrics\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ebee74ee-a340-4490-b2c6-1107951d6f5b', '9b5d83ef-2600-4c3b-b852-00607680277d', 4, NULL, '{\"title\": \"进阶之路：OpenAI的迭代策略：案例复盘\", \"points\": [\"核心矛盾：GPT-3.5在复杂逻辑推理与代码生成上的能力瓶颈，难以满足企业级专业需求\", \"关键动作：通过RLHF（人类反馈强化学习）优化对话质量，并推出Code Interpreter插件实现自主执行代码\", \"决策依据：从单一文本生成转向‘工具调用’模式，将模型打造为可解决具体任务的智能助手\", \"经验启示：生态扩展比单纯提升参数规模更能快速建立竞争壁垒，需平衡开放性与安全性\", \"风险提示：多模态整合初期面临技术架构重构挑战，需警惕插件滥用带来的幻觉放大风险\"]}', '{\"text\": \"页面标题：进阶之路：OpenAI的迭代策略：案例复盘\\n\\n页面文字：\\n- 问题背景在于GPT-3.5难以满足企业在复杂逻辑推理与代码生成上的专业需求瓶颈。\\n- 关键动作是通过RLHF优化对话质量并推出Code Interpreter插件，实现自主执行代码。\\n- 经验启示表明生态扩展比单纯提升参数规模更能快速建立壁垒，需兼顾开放与安全。\\n- 风险提示多模态初期面临架构重构挑战，必须警惕插件滥用可能带来的幻觉放大风险。\", \"generated_at\": \"2026-03-09T08:14:15.317253\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/ebee74ee-a340-4490-b2c6-1107951d6f5b_v1.png', 'FAILED', '2026-03-09 08:13:44', '2026-03-09 09:20:26', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ec26c37c-bf48-4f6c-b4ec-298ebeca3ff8', '7a4f3408-ca73-4a61-998e-174a92497610', 17, NULL, '{\"page_id\": \"p18\", \"title\": \"课后拓展：资源推荐与学习路径\", \"layout_id\": \"group_collab\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p16\"], \"must_cover\": [\"官方文档链接\", \"优质教程网站\", \"插件推荐列表\", \"社区交流渠道\", \"课后拓展：资源推荐与学习路径的核心概念与背景\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"课后拓展：资源推荐与学习路径的核心概念与背景\", \"课后拓展：资源推荐与学习路径的关键方法与执行要点\", \"课后拓展：资源推荐与学习路径的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"a\", \"logical_page_id\": \"p18\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T01:38:01.267592\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 01:36:25', '2026-03-08 01:38:01', 'group_collab', '{\"title\": \"课后拓展：资源推荐与学习路径\", \"subtitle\": \"构建持续成长的数字资产生产体系。\", \"bullets\": [{\"icon\": \"fa-book\", \"text\": \"官方文档与核心教程。\", \"description\": \"提供主流建模软件的官方文档链接及高质量基础教程网站，确保技术原理理解准确。\"}, {\"icon\": \"fa-plug\", \"text\": \"高效插件推荐列表。\", \"description\": \"精选用于自动布线、硬表面倒角及UV优化的专业插件，提升复杂模型制作效率。\"}, {\"icon\": \"fa-users\", \"text\": \"社区交流渠道。\", \"description\": \"接入资深艺术家论坛与技术社群，获取关于布线原则与有机体塑造的最新实战经验。\"}, {\"icon\": \"fa-route\", \"text\": \"进阶学习路径图。\", \"description\": \"规划从基础拓扑到材质映射的完整学习路线，明确下一步攻克硬表面处理的方向。\"}, {\"icon\": \"fa-leaf\", \"text\": \"开源资源库访问。\", \"description\": \"开放包含高质量拓扑参考模型与PBR材质贴图的云端资源库，供日常练习使用。\"}], \"keyTakeaway\": \"利用优质资源填补技能短板，将工匠精神转化为可量化的生产力。\", \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ed04c6be-d805-4cc6-b140-c4f11a329a16', 'a4eba850-5434-409c-bcf0-b43c6ff24364', 11, '展望', '{\"page_id\": \"p11\", \"title\": \"展望未来：AGI之路与人机共生\", \"part\": \"展望\", \"points\": [\"多模态融合与神经符号系统将成为通向通用人工智能（AGI）的关键路径\", \"人机协作模式将取代单纯替代，人类负责决策与创意，AI 专注执行与优化\", \"建立全球统一的伦理规范与监管框架，确保 AI 发展可信、可控且可持续\"]}', '{\"text\": \"页面标题：展望未来：AGI之路与人机共生\\n\\n页面文字：\\n- 多模态融合与神经符号系统将成为通向通用人工智能（AGI）的关键路径，打破感知壁垒。\\n- 人机协作模式将取代单纯替代，人类负责决策与创意，AI专注执行与优化实现共赢。\\n- 建立全球统一的伦理规范与监管框架，确保 AI 发展可信、可控且可持续地造福人类。\\n站在新的起点，我们应携手共进，以智慧驾驭技术，开启人机共生的美好新篇章。\", \"generated_at\": \"2026-03-09T08:54:48.435842\"}', NULL, 'DESCRIPTION_GENERATED', '2026-03-09 08:54:35', '2026-03-09 08:54:49', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('ef7ee1ec-7d15-4268-8f23-b171586ee4c6', '8f10b0ec-ba8a-41c7-9730-10360d6d560d', 2, NULL, '{\"page_id\": \"p03\", \"title\": \"行业痛点与能力目标对比\", \"layout_id\": \"edu_tri_compare\", \"has_image\": true, \"keywords\": [\"暗色三分屏设计\", \"左红右绿高亮箭头\", \"数据流视觉隐喻\", \"模糊化背景图标\", \"深蓝网格纹理\"], \"depends_on\": [\"p02\"], \"must_cover\": [\"新手常见瓶颈分析\", \"行业标准工作流对比\", \"预期能力提升结果\", \"行业痛点与能力目标对比的核心概念与背景\", \"行业痛点与能力目标对比的关键方法与执行要点\"], \"promises_open\": [{\"promise_id\": \"pr_p03_1\", \"text\": \"接下来我们将展示核心建模管线结构，解决从零开始的逻辑断层问题\", \"must_cover\": [\"基础造型原理\", \"拓扑规范标准\"], \"target_page_ids\": [\"p16\"], \"is_hard\": true}], \"promises_close\": [], \"points\": [\"行业痛点与能力目标对比的核心概念与背景\", \"行业痛点与能力目标对比的关键方法与执行要点\", \"行业痛点与能力目标对比的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_compare\", \"layout_variant\": \"a\", \"logical_page_id\": \"p03\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-07T07:30:15.651357\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-07 07:23:27', '2026-03-08 01:01:15', 'edu_tri_compare', '{\"title\": \"行业痛点与能力目标对比\", \"badge\": \"进阶能力验证\", \"columns\": [{\"title\": \"新手现状痛点\", \"points\": [\"缺乏空间思维导致比例尺偏差\", \"布线拓扑混乱影响动画绑定\", \"过度依赖插件忽视底层逻辑\", \"渲染效果单一光影氛围不足\"]}, {\"title\": \"行业标准流程\", \"points\": [\"遵循标准拓扑边缘循环流畅\", \"UV 拆分规范最大化贴图资源\", \"物理真实感光照模拟环境\", \"建立资产库提升协作效率\"]}, {\"title\": \"目标能力成果\", \"points\": [\"具备独立承担高质量场景搭建能力\", \"优化模型面数满足游戏引擎要求\", \"掌握全流程管线快速迭代设计\", \"产出符合商业交付标准成果\"]}], \"left\": {\"header\": \"维度一\", \"content\": [\"行业痛点与能力目标对比在维度一下的核心结论与适用条件。\"], \"bullets\": []}, \"right\": {\"header\": \"维度二\", \"content\": [\"行业痛点与能力目标对比在维度二下的核心结论与适用条件。\"], \"bullets\": []}, \"variant\": \"a\", \"layout_variant\": \"a\", \"layout_archetype\": \"feature_compare\"}');
