INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f5e7b272-4c48-4770-a4a8-f23f11512331', '9b5d83ef-2600-4c3b-b852-00607680277d', 0, '引言', '{\"page_id\": \"p01\", \"title\": \"封面：生成式AI的演进与变革\", \"part\": \"引言\", \"points\": [\"梳理从早期概念萌芽到当前技术全面爆发的关键时间轴节点\", \"深度聚焦ChatGPT、Claude、Gemini三大核心模型的技术突破\", \"系统阐述生成式AI的发展脉络、差异化定位及未来演进趋势\"]}', '{\"text\": \"页面标题：封面：生成式AI的演进与变革\\n\\n页面文字：\\n- 梳理从早期概念萌芽到当前技术全面爆发的关键时间轴节点，构建清晰发展脉络。\\n- 深度聚焦ChatGPT、Claude、Gemini三大核心模型的技术突破，解析其差异化定位。\\n- 系统阐述生成式AI的发展脉络、未来演进趋势及行业变革方向。\", \"generated_at\": \"2026-03-09T08:14:14.359464\"}', '9b5d83ef-2600-4c3b-b852-00607680277d/pages/f5e7b272-4c48-4770-a4a8-f23f11512331_v2.png', 'COMPLETED', '2026-03-09 08:13:36', '2026-03-09 09:20:42', NULL, NULL);
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f70bb515-44cf-4d65-aefb-acf1e6a42bc3', '14c0f24c-10e7-4309-a927-d9db1066897c', 3, NULL, '{\"page_id\": \"p04\", \"title\": \"三维坐标系的本质理解\", \"layout_id\": \"infographic_flow\", \"has_image\": false, \"keywords\": [], \"depends_on\": [\"p03\"], \"must_cover\": [\"X/Y/Z轴定义\", \"右手定则\", \"原点概念\", \"三维坐标系的本质理解的核心概念与背景\", \"三维坐标系的本质理解的关键方法与执行要点\"], \"promises_open\": [], \"promises_close\": [], \"points\": [\"三维坐标系的本质理解的核心概念与背景\", \"三维坐标系的本质理解的关键方法与执行要点\", \"三维坐标系的本质理解的应用场景与注意事项\"], \"required_close_promise_ids\": [], \"layout_archetype\": \"feature_list\", \"layout_variant\": \"b\", \"logical_page_id\": \"p04\"}', '{\"continuity\": {\"closed_promise_ids\": [], \"missing_required_close_promise_ids\": []}, \"generated_at\": \"2026-03-08T02:05:59.773740\"}', NULL, 'HTML_MODEL_GENERATED', '2026-03-08 02:04:43', '2026-03-08 02:06:00', 'infographic_flow', '{\"title\": \"三维坐标系的本质理解\", \"bullets\": [{\"icon\": \"fa-solid fa-cube\", \"text\": \"三轴定义与空间原点。\", \"description\": \"确立X（左右）、Y（上下）、Z（前后）的垂直关系，原点(0,0,0)作为所有空间计算的绝对基准点。\"}, {\"icon\": \"fa-solid fa-hand-paper\", \"text\": \"右手定则的空间映射。\", \"description\": \"通过拇指、食指、中指分别对应X、Y、Z轴正方向，建立符合人类直觉的三维空间定向逻辑。\"}, {\"icon\": \"fa-solid fa-layer-group\", \"text\": \"从二维到三维的本质跃迁。\", \"description\": \"坐标系不仅是定位工具，更是将平面几何逻辑扩展为体积运算的底层数学框架。\"}, {\"icon\": \"fa-solid fa-ruler-combined\", \"text\": \"度量与比例的物理基准。\", \"description\": \"将虚拟单位转化为现实世界的物理尺寸，确保模型比例在渲染和工程应用中的准确性。\"}, {\"icon\": \"fa-solid fa-brain\", \"text\": \"空间拓扑的思维构建。\", \"description\": \"理解坐标网格背后的拓扑结构，为后续的多边形生成与变形提供逻辑支撑。\"}], \"keyTakeaway\": \"三维坐标系是连接抽象数学与具象视觉的桥梁，掌握其本质是精准建模的基石。\", \"variant\": \"b\", \"layout_variant\": \"b\", \"layout_archetype\": \"feature_list\"}');
INSERT INTO `pages` (`id`, `project_id`, `order_index`, `part`, `outline_content`, `description_content`, `generated_image_path`, `status`, `created_at`, `updated_at`, `layout_id`, `html_model`) VALUES ('f9b6bc4c-7044-432f-8868-c0aa21e8ed21', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564', 7, '技能实操', '{\"page_id\": \"p06\", \"title\": \"有机生物建模技巧\", \"part\": \"技能实操\", \"points\": [\"利用数字雕刻工具精准塑造肌肉走向与皮肤褶皱细节\", \"采用对称建模提升效率，结合局部细化策略优化关键区域\", \"融入基础解剖学知识确保角色结构合理且符合生理逻辑\", \"掌握拓扑布线对表情变形与动态流畅度的关键影响\"]}', '{\"text\": \"页面标题：有机生物建模技巧\\n\\n页面文字：\\n- 利用数字雕刻工具精准塑造肌肉走向与皮肤褶皱，赋予角色生动细节。\\n- 采用对称建模提升效率，结合局部细化策略重点优化面部等关键区域。\\n- 融入基础解剖学知识确保角色结构合理，使形态完全符合生理逻辑。\\n- 深刻理解拓扑布线对表情变形的影响，保障角色动态表演的流畅自然。\", \"generated_at\": \"2026-03-09T03:39:37.135422\"}', 'cf6b430a-4e52-4c4b-9725-ec266ef3c564/pages/f9b6bc4c-7044-432f-8868-c0aa21e8ed21_v1.png', 'COMPLETED', '2026-03-09 03:39:17', '2026-03-09 03:45:49', NULL, NULL);
